<script>
setTimeout(function() {
    const toggleBtn = document.querySelector('.toggle-btn');
    const btnGroup = document.querySelector('.btn-group');
    if (toggleBtn && btnGroup) {
        toggleBtn.addEventListener('click', () => {
            btnGroup.classList.toggle('hidden');
            toggleBtn.textContent = btnGroup.classList.contains('hidden') ? 'Mở rộng' : 'Thu gọn';
        });
    }
    document.querySelectorAll('.action-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            const msg = btn.getAttribute('data-action');
            if (!msg) return;

            // Xóa active từ các nút khác
            document.querySelectorAll('.action-btn').forEach(b => b.classList.remove('active'));

            // Thêm active cho nút hiện tại
            btn.classList.add('active');

            try {
                const input = window.parent.document.querySelector('#send_textarea');
                if (input) {
                    const cur = input.value.trim();
                    input.value = cur ? cur + '\n' + msg : msg;
                    input.dispatchEvent(new Event('input', { bubbles: true }));
                }
            } catch (e) { console.error(e); }
        });
    });
}, 100);
</script>
