            font-family: 'Playfair Display', serif;
            color: var(--novel-accent);
            font-weight: 700;
            opacity: 0.6; /* Độ mờ chế độ ban ngày */
            line-height: 1;
        }

        /* Làm sáng chữ cái đầu ở chế độ ban đêm */
        .novel-header-container.night-mode .novel-preface::first-letter {
            opacity: 0.9;
