            }
            .butterfly-deco.bottom-left {
                width: 90px;
                height: 90px;
                bottom: -15px;
                left: -25px;
            }
        }
    </style>

    <!-- SVG bướm -->
    <svg class="butterfly-deco top-right" viewBox="0 0 100 100">
