    <div class="novel-content-wrapper">
        <!-- Nút chuyển đổi -->
        <button class="theme-btn-base theme-toggle-btn" title="Chuyển đổi chế độ ngày/đêm">
            <span class="toggle-icon"></span>
        </button>
        <!-- Bảng điều khiển nổi màu chủ đề -->
        <div class="theme-color-dropdown" id="color-dropdown">
            <button class="theme-btn-base color-dropdown-btn" title="Thay đổi màu chủ đề" onclick="toggleColorPanel(event)">
                <!-- Biểu tượng màu tối giản hơn (hình giọt nước/cọ vẽ) -->
                <svg viewBox="0 0 24 24">
                    <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10c1.38 0 2.5-1.12 2.5-2.5 0-.53-.21-1.04-.58-1.41-.36-.37-.58-.88-.58-1.41 0-1.11.89-2 2-2h1.67c2.76 0 5-2.24 5-5 0-4.42-4.03-8-9-8zm-5.5 9c-.83 0-1.5-.67-1.5-1.5S5.67 8 6.5 8 8 8.67 8 9.5 7.33 11 6.5 11zm3-4c-.83 0-1.5-.67-1.5-1.5S8.67 4 9.5 4 11 4.67 11 5.5 10.33 7 9.5 7zm5 0c-.83 0-1.5-.67-1.5-1.5S13.67 4 14.5 4 16 4.67 16 5.5 15.33 7 14.5 7zm3 4c-.83 0-1.5-.67-1.5-1.5S16.67 8 17.5 8 19 8.67 19 9.5 18.33 11 17.5 11z"/>
                </svg>
            </button>
            <div class="color-panel">
                <div class="color-panel-row">
                    <!-- Cài sẵn: Đỏ thẫm -->
                    <button class="color-preset-btn" style="--preset-color: #c42e2e;" title="Đỏ thẫm" onclick="setPresetColor(this, '#c42e2e')"></button>
                    <!-- Cài sẵn: Xanh thẳm -->
                    <button class="color-preset-btn" style="--preset-color: #3d50e4;" title="Xanh thẳm" onclick="setPresetColor(this, '#2e6bc4')"></button>
                    <!-- Cài sẵn: Đêm tím -->
                    <button class="color-preset-btn" style="--preset-color: #633f96;" title="Đêm tím" onclick="setPresetColor(this, '#7942c4')"></button>

                    <div class="color-panel-divider"></div>

                    <!-- Bộ chọn tùy chỉnh -->
                    <div class="custom-color-wrapper" title="Màu tùy chỉnh">
                        <input type="color" class="night-color-picker-input" value="#c42e2e">
