        (function () {
            const app  = document.getElementById('ghostCalendarApp');
            const icon = document.getElementById('themeIcon');
            const STORAGE_KEY = 'ghost-calendar-theme';

            function initTheme() {
                if (localStorage.getItem(STORAGE_KEY) === 'night') {
                    app.classList.add('night-mode');
                    icon.textContent = '☀';
                }
            }
            window.toggleGhostTheme = function () {
                app.classList.toggle('night-mode');
                const isNight = app.classList.contains('night-mode');
                icon.textContent = isNight ? '☀' : '☾';
                localStorage.setItem(STORAGE_KEY, isNight ? 'night' : 'day');
            };
            initTheme();

            // === Parse dữ liệu ===
            const rawDataContainer = document.getElementById('calendar-raw-data-switch');
            if (!rawDataContainer) return;
            const rawString = rawDataContainer.textContent.trim();
            const lines = rawString.split(/\r?\n/);
            const calendarData = [];
            let currentDayObj = null;

            lines.forEach(line => {
                line = line.trim();
                if (!line) return;
                // Sửa đổi regex split để hỗ trợ cả dấu '|' và '｜' (full-width)
                if (line.startsWith('Date:')) {
                    const parts = line.replace('Date:', '').split(/\||｜/).map(s => s.trim());
                    if (parts.length >= 1) {
                        currentDayObj = { dateStr: parts[0], dayName: parts[1] || '', events: [] };
                        calendarData.push(currentDayObj);
                    }
                } else if (line.startsWith('Event:') && currentDayObj) {
                    const parts = line.replace('Event:', '').split(/\||｜/).map(s => s.trim());
                    if (parts.length >= 5) {
                        currentDayObj.events.push({
                            type: parts[0], title: parts[1], description: parts[2],
