            function buildInputText(events) {
                if (!events?.length) return '';
                if (events.length === 1) {
                    const ev = events[0];
                    const dateLabel = `${ev.dateStr}${ev.dayName ? ` ${ev.dayName}` : ''}`.trim();
                    const npcLabel  = ev.npcAction?.trim() ? `Thông tin bổ sung là: ${ev.npcAction}.` : '';
                    return [`Vui lòng đẩy thời gian cốt truyện đến ${dateLabel} lúc ${ev.time}, bắt đầu triển khai từ lịch trình ${translateType(ev.type)} mang tên "${ev.title}".`,
                            `Địa điểm hiện tại là ${ev.location}, nội dung chính của lịch trình này là: ${ev.description}.`,
                            npcLabel].filter(Boolean).join(' ');
                }
                return ['Vui lòng bắt đầu tiến triển cốt truyện lần này từ các lịch trình đã chọn dưới đây, và triển khai kết nối tự nhiên theo trình tự thời gian:',
                        ...events.map((ev, i) => `${i + 1}. ${formatEventPrompt(ev)}`),
                        'Vui lòng mặc định bắt đầu đẩy thời gian từ lịch trình đầu tiên, và tổng hợp những sắp xếp này thành một quá trình cốt truyện mạch lạc.'].join('\n');
            }

            function getSelectedEvents() {
                return Array.from(selectedEventIds).map(id => eventLookup.get(id)).filter(Boolean)
                    .sort((a, b) => a.dayIndex - b.dayIndex || a.eventIndex - b.eventIndex);
            }

            function updateSelectionUI() {
                const count = selectedEventIds.size;
                if (selectionCount) selectionCount.textContent = String(count);
                if (composeBtn) {
                    composeBtn.disabled = count === 0;
                    composeBtn.textContent = count > 0 ? `Tiến triển lịch trình đã chọn (${count})` : 'Tiến triển lịch trình đã chọn';
                }
                if (clearSelectionBtn) clearSelectionBtn.disabled = count === 0;
                if (selectionHint) {
                    selectionHint.textContent = count > 0
                        ? `Đã chọn ${count} lịch trình, nhấp vào nút bên phải để sắp xếp thành một lời nhắc tiến triển cốt truyện.`
                        : 'Nhấp vào "Thêm vào cốt truyện" ở bên phải mỗi lịch trình để chọn nhiều mục.';
                }
            }

            async function fallbackSetInput(text) {
                try {
                    const hostWindow   = window.parent && window.parent !== window ? window.parent : window;
                    const hostDocument = hostWindow.document;
                    const selectors    = ['#send_textarea', 'textarea#send_textarea', 'textarea[name="user_input"]', '#chat-input textarea', 'textarea'];
                    let inputEl = null;
                    selectors.some(sel => {
                        const found = Array.from(hostDocument.querySelectorAll(sel)).find(n => !n.disabled && !n.readOnly && (n.offsetParent !== null || sel === 'textarea'));
                        if (found) { inputEl = found; return true; }
                    });
                    if (!inputEl) return false;
                    inputEl.focus();
                    const proto      = inputEl.tagName === 'TEXTAREA' ? hostWindow.HTMLTextAreaElement.prototype : hostWindow.HTMLInputElement.prototype;
                    const descriptor = Object.getOwnPropertyDescriptor(proto, 'value');
                    if (descriptor?.set) descriptor.set.call(inputEl, text);
                    else inputEl.value = text;
                    inputEl.dispatchEvent(new hostWindow.Event('input',  { bubbles: true }));
                    inputEl.dispatchEvent(new hostWindow.Event('change', { bubbles: true }));
                    return true;
                } catch { return false; }
            }

            async function writeToUserInput(text, title, count = 1) {
                try {
                    if (typeof triggerSlash === 'function') {
                        await triggerSlash('/setinput ' + text);
                        setStatus(count > 1 ? `Đã ghi ${count} lịch trình vào ô nhập liệu.` : `Đã ghi "${title}" vào ô nhập liệu.`);
                        return;
                    }
                } catch {}
                const ok = await fallbackSetInput(text);
                if (ok) setStatus(count > 1 ? `Đã ghi ${count} lịch trình vào ô nhập liệu.` : `Đã ghi "${title}" vào ô nhập liệu.`);
                else setStatus('Không tìm thấy ô nhập liệu.', true);
            }

            // === Render ===
            function render() {
                scroller.innerHTML = '';
                const useSpread = calendarData.length > 0 && calendarData.length <= 8;
                scroller.classList.toggle('spread-layout', useSpread);

                calendarData.forEach((day, index) => {
                    const card = document.createElement('div');
                    card.className = `ghost-date-item ${index === 0 ? 'active' : ''}`;

                    // === FIX: Parse đúng format DD/MM ===
                    const dateParts = day.dateStr.trim().split(/[\/\-]/);
                    let dayNum, monthNum;
                    if (dateParts.length === 3 && dateParts[0].length === 4) {
                        // YYYY-MM-DD
                        dayNum   = dateParts[2];
                        monthNum = dateParts[1];
                    } else {
                        // DD/MM hoặc DD/MM/YYYY — parts[0]=ngày, parts[1]=tháng
                        dayNum   = dateParts[0];
                        monthNum = dateParts[1] || '';
                    }

                    let dotsHtml = '';
                    day.events.forEach(ev => {
                        dotsHtml += `<div class="ghost-dot" style="background-color:${getColorByType(ev.type)}"></div>`;
                    });

                    card.innerHTML = `
                        <span class="ghost-day-name">${day.dayName}</span>
                        <span class="ghost-day-num">${dayNum}</span>
                        ${monthNum ? `<span class="ghost-day-month">/${monthNum}</span>` : ''}
                        <div class="ghost-dots">${dotsHtml}</div>
                    `;

                    card.onclick = () => {
                        scroller.querySelectorAll('.ghost-date-item').forEach(c => c.classList.remove('active'));
                        card.classList.add('active');
                        renderEvents(day);
                    };
                    scroller.appendChild(card);
                });

                if (calendarData.length > 0) renderEvents(calendarData[0]);
                else eventList.innerHTML = '<div class="ghost-empty">Trống rỗng</div>';
            }

            function renderEvents(dayData) {
                activeDayData  = dayData;
                eventList.innerHTML = '';
                if (!dayData.events.length) {
                    eventList.innerHTML = '<div class="ghost-empty">Không có sắp xếp nào? Hãy nghỉ ngơi thật tốt nhé</div>';
                    return;
                }
                dayData.events.forEach(ev => {
                    const details = document.createElement('details');
                    details.className = `ghost-event-details type-${ev.type}`;
                    details.classList.toggle('selected', selectedEventIds.has(ev.id));
                    const isSelected = selectedEventIds.has(ev.id);

                    let contentHtml = `<div class="ghost-event-desc">${ev.description}</div>`;
                    if (ev.npcAction?.trim()) {
                        contentHtml += `<div class="ghost-event-npc-action">${ev.npcAction}</div>`;
                    }

                    details.innerHTML = `
                        <summary class="ghost-event-summary">
                            <div class="ghost-event-topline">
                                <div class="ghost-event-meta"><span>${ev.time}</span><span>·</span><span>${translateType(ev.type)}</span></div>
                                <button class="ghost-select-btn ${isSelected ? 'selected' : ''}" type="button" aria-pressed="${isSelected}">${isSelected ? 'Đã chọn ✦' : 'Thêm vào cốt truyện'}</button>
                            </div>
                            <div class="ghost-event-title">${ev.title}</div>
                            <div class="ghost-event-loc">@ ${ev.location}</div>
                        </summary>
                        <div class="ghost-event-content-wrapper">${contentHtml}</div>
                    `;

                    const selectBtn = details.querySelector('.ghost-select-btn');
                    selectBtn.addEventListener('click', e => {
                        e.preventDefault(); e.stopPropagation();
                        if (selectedEventIds.has(ev.id)) selectedEventIds.delete(ev.id);
                        else selectedEventIds.add(ev.id);
                        const sel = selectedEventIds.has(ev.id);
                        details.classList.toggle('selected', sel);
                        selectBtn.classList.toggle('selected', sel);
                        selectBtn.setAttribute('aria-pressed', sel);
                        selectBtn.textContent = sel ? 'Đã chọn ✦' : 'Thêm vào cốt truyện';
                        updateSelectionUI();
                    });

                    eventList.appendChild(details);
                });
            }

            composeBtn?.addEventListener('click', () => {
                const sel = getSelectedEvents();
                if (!sel.length) return;
                const title = sel.length === 1 ? sel[0].title : `${sel.length} lịch trình đã chọn`;
                writeToUserInput(buildInputText(sel), title, sel.length);
            });

            clearSelectionBtn?.addEventListener('click', () => {
                selectedEventIds.clear();
                updateSelectionUI();
                if (activeDayData) renderEvents(activeDayData);
                setStatus('Đã xóa các lịch trình đã chọn.');
            });

            calendarData.forEach((day, dayIndex) => {
                day.dayIndex = dayIndex;
                day.events.forEach((ev, eventIndex) => {
                    ev.id = `${dayIndex}-${eventIndex}`;
                    ev.dayIndex   = dayIndex;
                    ev.eventIndex = eventIndex;
                    ev.dateStr    = day.dateStr;
                    ev.dayName    = day.dayName;
                    eventLookup.set(ev.id, ev);
                });
            });

            updateSelectionUI();
            render();
        })();
    </script>
</body>
</html>
