    // Ngoại hình bóng nổi - Bóng kính (Tăng cường độ trong suốt)
    function applyBallAppearance() {
      const doc = window.parent.document;
      const ball = doc.getElementById(FLOATING_BALL_ID);
      if (!ball) return;

      const c = settings.ballColor || { r: 240, g: 240, b: 240, a: 0.6 };
      const mode = settings.themeMode || "light";
      const accent = { r: c.r, g: c.g, b: c.b };

      // Hiệu ứng bóng kính - Độ trong suốt cực cao
      if (mode === "dark") {
        // Bóng kính tối
        ball.style.background = `radial-gradient(circle at 30% 30%, rgba(255,255,255,0.25), transparent 50%),
                                 radial-gradient(circle at 70% 80%, ${toRgba(accent, 0.5)}, transparent 50%),
                                 rgba(40, 45, 60, 0.5)`; // 0.85 -> 0.5
        ball.style.boxShadow = `0 8px 32px rgba(0,0,0,0.3),
                                inset 0 0 0 1px rgba(255,255,255,0.1),
                                inset 0 1px 1px rgba(255,255,255,0.3),
                                0 0 15px ${toRgba(accent, 0.3)}`;
        ball.style.border = "1px solid rgba(255,255,255,0.1)";
      } else {
        // Bóng kính sáng
        ball.style.background = `radial-gradient(circle at 30% 30%, rgba(255,255,255,0.2), transparent 50%),
                                 radial-gradient(circle at 70% 80%, ${toRgba(accent, 0.4)}, transparent 50%),
                                 rgba(255, 255, 255, 0.4)`; // 0.85 -> 0.4
        ball.style.boxShadow = `0 8px 24px rgba(0,0,0,0.1),
                                inset 0 0 0 1px rgba(255,255,255,0.6),
                                inset 0 1px 4px rgba(255,255,255,0.8),
                                0 0 10px ${toRgba(accent, 0.2)}`;
        ball.style.border = "1px solid rgba(255,255,255,0.4)";
      }

      ball.style.backdropFilter = "blur(8px) saturate(140%)";
      ball.style.webkitBackdropFilter = "blur(8px) saturate(140%)";
      ball.style.borderRadius = "50%";
      ball.style.zIndex = "2147483646";
      const icon = ball.querySelector("i");
      if (icon) {
        icon.style.color = mode === "dark" ? "#ffffff" : "#111111";
        icon.style.textShadow =
          mode === "dark" ? "0 2px 4px rgba(0,0,0,0.5)" : "none";
        icon.style.filter = "drop-shadow(0 1px 2px rgba(0,0,0,0.1))";
      }
    }

    // Tương thích iOS: Ngăn tự động phóng to khi nhấp vào ô nhập liệu
    // Không sửa đổi viewport meta (sẽ ảnh hưởng đến chức năng gốc của trang tavern), thay vào đó dùng CSS đảm bảo font-size của input >= 16px
    function ensureZoomEnabled() {
      try {
        const doc = window.parent.document;
        const ZOOM_FIX_ID = "pt-ios-zoom-fix";
        if (doc.getElementById(ZOOM_FIX_ID)) return;

        // Phát hiện thiết bị iOS (iPhone/iPad/iPod)
        const ua = window.parent.navigator.userAgent || "";
        const isIOS =
          /iPad|iPhone|iPod/.test(ua) ||
          (ua.includes("Mac") && "ontouchend" in doc);
        if (!isIOS) return; // Không phải iOS thì không cần xử lý

        // Trên iOS, font-size của input < 16px sẽ làm trang tự động phóng to
        // Chỉ đặt font-size cho các phần tử panel của script, không ảnh hưởng đến phần khác của tavern
        const style = doc.createElement("style");
        style.id = ZOOM_FIX_ID;
        style.textContent = `
                #${PANEL_ID} input,
                #${PANEL_ID} textarea,
                #${PANEL_ID} select,
                #${QUICK_MENU_ID} input,
                #${QUICK_MENU_ID} textarea,
                #${QUICK_MENU_ID} select,
                #${CUSTOMIZE_PANEL_ID} input,
                #${CUSTOMIZE_PANEL_ID} textarea,
                #${CUSTOMIZE_PANEL_ID} select {
                    font-size: 16px !important;
                }
            `;
        doc.head.appendChild(style);
      } catch (e) {
        log("Tương thích tỷ lệ iOS thất bại:", e);
      }
    }
    function fitQuickMenu() {
      try {
        const vv = window.parent.visualViewport;
        const vh = vv ? vv.height : window.parent.innerHeight;
        const menu = window.parent.document.getElementById(QUICK_MENU_ID);
        if (!menu) return;
        const maxH = Math.round(vh * 0.86);
        menu.style.maxHeight = `${maxH}px`;
        menu.style.boxSizing = "border-box";
      } catch (e) {}
    }
    function fitMainPanel() {
      try {
        const vv = window.parent.visualViewport;
        const vh = vv ? vv.height : window.parent.innerHeight;
        const vw = vv ? vv.width : window.parent.innerWidth;
        const panel = window.parent.document.getElementById(PANEL_ID);
        if (!panel) return;
        panel.style.height = "auto";
        panel.style.maxHeight = Math.round(vh * 0.86) + "px";
        panel.style.maxWidth = Math.round(vw * 0.94) + "px";
      } catch (e) {}
    }
    function alignVisibleOverlays() {
      const vv = window.parent.visualViewport;
      if (!vv) return;
      const doc = window.parent.document;
      const overlays = [
        doc.querySelector(`.${MAIN_OVERLAY_CLS}`),
        doc.querySelector(`.${QUICK_OVERLAY_CLS}`),
        doc.querySelector(`.${CUSTOMIZE_OVERLAY_CLS}`),
      ];
      overlays.forEach((el) => {
        if (!el || el.style.display === "none") return;
        const s = el.style;
        s.position = "fixed";
        s.left = vv.offsetLeft + "px";
        s.top = vv.offsetTop + "px";
        s.width = vv.width + "px";
        s.height = vv.height + "px";
      });
    }
    function lockScroll(parentDoc) {
      // Tối ưu hóa: Dùng overflow: hidden thay cho position: fixed
      // Như vậy body vẫn nằm trong luồng tài liệu, chiều cao sidebar sẽ không tính sai
      if (parentDoc.body.style.overflow !== "hidden") {
        // Lưu lại trạng thái overflow trước đó để khôi phục
        parentDoc.body.dataset.ptOriginalOverflow =
          parentDoc.body.style.overflow || "";
        parentDoc.body.style.overflow = "hidden";
      }
    }

    function unlockScroll(parentDoc) {
      // Khôi phục trạng thái overflow trước đó
      if (parentDoc.body.dataset.ptOriginalOverflow !== undefined) {
        parentDoc.body.style.overflow =
          parentDoc.body.dataset.ptOriginalOverflow;
        delete parentDoc.body.dataset.ptOriginalOverflow;
      } else {
        // Dọn dẹp dự phòng
        parentDoc.body.style.overflow = "";
      }
    }
    function anyOverlayVisible() {
      const d = window.parent.document;
      const sel = (e) => !!e && e.style.display !== "none";
      return (
        sel(d.querySelector(`.${MAIN_OVERLAY_CLS}`)) ||
        sel(d.querySelector(`.${QUICK_OVERLAY_CLS}`)) ||
        sel(d.querySelector(`.${CUSTOMIZE_OVERLAY_CLS}`))
      );
    }

    async function togglePromptEnabled(target, enabled) {
      try {
        await window.parent.TavernHelper.updatePresetWith(
          "in_use",
          (preset) => {
            let changed = false;
            if (target.id) {
              const p = preset.prompts.find((x) => x.id === target.id);
              if (p) {
                p.enabled = enabled;
                changed = true;
              }
            }
            if (!changed && target.name) {
              const list = preset.prompts.filter(
                (x) => (x.name || "") === target.name,
              );
              if (list.length) {
                const i = clamp(target.idx || 1, 1, list.length) - 1;
                list[i].enabled = enabled;
                changed = true;
              }
            }
            return preset;
          },
        );
      } catch (error) {
        log("Cập nhật preset thời gian thực bị lỗi:", error);
        toastr?.error?.("Chuyển đổi trạng thái mục thất bại!");
      }
    }

    // --- Render UI ---
    function renderCurrentFunctionView() {
      const tab = settings.currentFunctionTab || "preset";
      if (tab === "worldbook") {
        populateWorldbookMainMenu();
      } else {
        populatePresetMainMenu();
      }
    }

    function populateMainMenu() {
      renderCurrentFunctionView();
    }

    function populatePresetMainMenu() {
      const all = getAllSillyTavernPresets();
      const loadedPresetName = window.parent.TavernHelper.getLoadedPresetName();
      const parent$ = window.parent.$;
      const $panel = parent$(`#${PANEL_ID}`);
      const $content = $panel.find(".panel-content");
      $panel.find(".footer-back-button").hide();
      $content.empty();

      // Thẻ chuyển đổi chức năng
      const $funcTabs =
        parent$(`<div class="function-tabs" role="tablist" aria-label="Chuyển đổi chức năng">
            <button class="func-tab-btn active" data-func="preset" role="tab" aria-selected="true"><i class="fa-solid fa-list"></i> Mục Preset</button>
            <button class="func-tab-btn" data-func="worldbook" role="tab" aria-selected="false"><i class="fa-solid fa-book"></i> Thế giới thư</button>
        </div>`);
      $content.append($funcTabs);

      if (Object.keys(all).length === 0) {
        $content.append("<p>Không thể tải bất kỳ preset hợp lệ nào.</p>");
        return;
      }

      const $list = parent$('<div class="preset-list"></div>');
      const $cur = parent$(
        '<div class="list-group-item interactable preset-list-item current-preset" role="button" tabindex="0" aria-label="Preset đang sử dụng"></div>',
      ).attr("data-preset-name", loadedPresetName);
      $cur.append("<b>Đang sử dụng:</b> ");
      $cur.append(
        parent$('<span class="preset-name-bold"></span>').text(
          loadedPresetName,
        ),
      );
      $list.append($cur);

      for (const name in all) {
        if (name === loadedPresetName || name === "in_use") continue;
        const $item = parent$(
          '<div class="list-group-item interactable preset-list-item" role="button" tabindex="0"></div>',
        )
          .attr("data-preset-name", name)
          .text(name);
        $list.append($item);
      }
      $content.append($list);
      $content.scrollTop(lastScrollPosition);

      // Liên kết sự kiện chuyển đổi chức năng
      $funcTabs.on("click", ".func-tab-btn", function () {
        const func = parent$(this).data("func");
        if (func === settings.currentFunctionTab) return;
        settings.currentFunctionTab = func;
        saveSettings();
        renderCurrentFunctionView();
      });
    }

    function populateWorldbookMainMenu() {
      const parent$ = window.parent.$;
      const $panel = parent$(`#${PANEL_ID}`);
      const $content = $panel.find(".panel-content");
      $panel.find(".footer-back-button").hide();
      $content.empty();

      // Tự động dọn dẹp các thế giới thư không tồn tại
      cleanupInvalidWorldbooks();

      // Thẻ chuyển đổi chức năng
      const $funcTabs =
        parent$(`<div class="function-tabs" role="tablist" aria-label="Chuyển đổi chức năng">
            <button class="func-tab-btn" data-func="preset" role="tab" aria-selected="false"><i class="fa-solid fa-list"></i> Mục Preset</button>
            <button class="func-tab-btn active" data-func="worldbook" role="tab" aria-selected="true"><i class="fa-solid fa-book"></i> Thế giới thư</button>
        </div>`);
      $content.append($funcTabs);

      // Lấy danh sách thế giới thư
      let worldbookNames = [];
      try {
        worldbookNames = window.parent.TavernHelper.getWorldbookNames() || [];
      } catch (e) {
        log("Lấy danh sách thế giới thư thất bại:", e);
        $content.append("<p>Không thể tải danh sách thế giới thư.</p>");
        return;
      }

      let globalEnabled = [];
      try {
        globalEnabled =
          window.parent.TavernHelper.getGlobalWorldbookNames() || [];
      } catch (e) {
        log("Lấy thế giới thư toàn cục thất bại:", e);
      }

      ensureWorldbookOrderArray();
      ensureWorldbookGroupsCleanup();
      let selectedViewMode = "grouped";

      const $header = parent$('<div class="view-header"></div>').append(
        parent$("<h5></h5>").text("Quản lý Thế giới thư"),
      );
      const $tabs = parent$(
        `<div class="tabs" role="tablist" aria-label="Chuyển đổi chế độ xem Thế giới thư"><button class="tab-btn active" data-tab="all" role="tab" aria-selected="true">Tất cả Thế giới thư</button><button class="tab-btn" data-tab="selected" role="tab" aria-selected="false">Đã chọn</button></div>`,
      );
      const $toolbar = parent$(
        `<div class="prompt-toolbar"><input id="pt-wb-search" type="text" placeholder="Tìm kiếm thế giới thư (từ khóa tên)" aria-label="Tìm kiếm thế giới thư" /></div>`,
      );
      const $topbarRow = parent$('<div class="prompt-view-topbar-row"></div>')
        .append($header)
        .append($tabs);
      const $topbar = parent$('<div class="prompt-view-topbar"></div>')
        .append($topbarRow)
        .append($toolbar);
      const $panels = parent$(
        `<div class="tabs-panels" data-type="worldbook"><div class="tab-panel tab-all"></div><div class="tab-panel tab-selected" style="display:none;"></div></div>`,
      );
      const $allWrap = $panels.find(".tab-all");
      const $selWrap = $panels.find(".tab-selected");

      // Render danh sách tất cả thế giới thư
      const $all = parent$('<div class="prompts-all wb-all"></div>');
      $allWrap.append($all);

      worldbookNames.forEach((wbName) => {
        const checked = isWorldbookSelected(wbName);
        const isGlobal = globalEnabled.includes(wbName);

        const $label = parent$('<label class="prompt-item wb-item"></label>')
          .attr("data-name", wbName.toLowerCase())
          .attr("data-wb-name", wbName)
          .attr("title", wbName);

        if (checked) $label.addClass("is-selected");
        if (isGlobal) $label.addClass("is-global");

        const $cb = parent$('<input type="checkbox" class="pt-wb-check"/>')
          .prop("checked", checked)
          .attr("data-wb-name", wbName);

        const $span = parent$("<span></span>").text(wbName);
        const $globalBadge = isGlobal
          ? parent$(
              '<span class="wb-global-badge" title="Đã bật toàn cục">🌐</span>',
            )
          : parent$("<span></span>");

        $label.append($cb).append($span).append($globalBadge);
        $all.append($label);
      });

      // Thanh công cụ chế độ xem đã chọn
      const $selToolbar = parent$(
        `<div class="sel-toolbar"><div class="sel-toolbar-left"><button type="button" class="sel-add-group-btn">Nhóm mới</button><button type="button" class="sel-expand-groups-btn">Mở rộng tất cả</button><button type="button" class="sel-collapse-groups-btn">Thu gọn tất cả</button></div><div class="sel-toolbar-right"><button type="button" class="sel-view-mode-btn active" data-mode="grouped">Theo nhóm</button><button type="button" class="sel-view-mode-btn" data-mode="flat">Tất cả danh sách</button></div></div>`,
      );
      const $selList = parent$(
        '<div class="sel-list wb-sel-list" aria-label="Thế giới thư đã chọn, có thể kéo để sắp xếp"></div>',
      );
      $selWrap.append($selToolbar).append($selList);

      // Render danh sách đã chọn
      function renderSelectedFlat() {
        const m = getSelectedWorldbooks();
        const order = getWorldbookOrder();
        const globalEnabled =
          window.parent.TavernHelper.getGlobalWorldbookNames() || [];
        $selList.empty();
        order.forEach((wbName) => {
          if (!m[wbName]) return;
          const isGlobal = globalEnabled.includes(wbName);
          const row = parent$(
            `<div class="sel-row wb-sel-row" data-wb-name="${wbName}"><span class="drag-handle" title="Kéo để sắp xếp" aria-hidden="true">☰</span><span class="pill-text" title="${wbName}" style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${wbName}</span>${isGlobal ? '<span class="wb-global-indicator">🌐</span>' : ""}<button class="pill-group" title="Cài đặt nhóm" aria-label="Cài đặt nhóm"><i class="fa-solid fa-list-ul"></i></button><button class="pill-remove" title="Hủy thế giới thư này" aria-label="Hủy"><i class="fa-solid fa-times"></i></button></div>`,
          );
          $selList.append(row);
        });
      }

      function renderSelectedGrouped() {
        const m = getSelectedWorldbooks();
        const order = getWorldbookOrder();
        const groups = getWorldbookGroups();
        const globalEnabled =
          window.parent.TavernHelper.getGlobalWorldbookNames() || [];
        ensureWorldbookGroupsCleanup();
        const groupedSet = new Set();
        const groupDisplay = new Map();
        groups.forEach((g) => {
          const list = (g.members || []).filter((name) => !!m[name]);
          if (list.length) {
            groupDisplay.set(g.id, list);
            list.forEach((name) => groupedSet.add(name));
          }
        });
        const ungrouped = [];
        order.forEach((name) => {
          if (!m[name]) return;
          if (!groupedSet.has(name)) ungrouped.push(name);
        });

        $selList.empty();
        const makeRow = (wbName) => {
          if (!m[wbName]) return null;
          const isGlobal = globalEnabled.includes(wbName);
          return parent$(
            `<div class="sel-row wb-sel-row" data-wb-name="${wbName}"><span class="drag-handle" title="Kéo để sắp xếp" aria-hidden="true">☰</span><span class="pill-text" title="${wbName}" style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${wbName}</span>${isGlobal ? '<span class="wb-global-indicator">🌐</span>' : ""}<button class="pill-group" title="Cài đặt nhóm" aria-label="Cài đặt nhóm"><i class="fa-solid fa-list-ul"></i></button><button class="pill-remove" title="Hủy thế giới thư này" aria-label="Hủy"><i class="fa-solid fa-times"></i></button></div>`,
          );
        };

        groups.forEach((g) => {
          const names = groupDisplay.get(g.id) || [];
          const $group = parent$(
            '<div class="sel-group wb-sel-group"></div>',
          ).attr("data-gid", g.id);
          if (g.collapsed) $group.addClass("collapsed");
          const $gh = parent$(
            `<div class="sel-group-header"><span class="sel-group-arrow" aria-hidden="true">▾</span><span class="sel-group-title"></span><div class="sel-group-actions"><button class="sel-group-drag" title="Kéo để sắp xếp nhóm" aria-label="Kéo để sắp xếp nhóm"><i class="fa-solid fa-bars"></i></button><button class="sel-group-add" title="Thêm thế giới thư vào nhóm này" aria-label="Thêm thế giới thư"><i class="fa-solid fa-plus"></i></button><button class="sel-group-rename" title="Đổi tên nhóm" aria-label="Đổi tên"><i class="fa-solid fa-pen"></i></button><button class="sel-group-delete" title="Xóa nhóm (không hủy chọn thế giới thư)" aria-label="Xóa nhóm"><i class="fa-solid fa-trash"></i></button></div></div>`,
          );
          $gh.find(".sel-group-title").text(g.name);
          const $body = parent$('<div class="sel-group-body"></div>');
          names.forEach((name) => {
            const $row = makeRow(name);
            if ($row) $body.append($row);
          });
          $group.append($gh).append($body);
          $selList.append($group);
        });

        if (ungrouped.length) {
          const $group = parent$(
            '<div class="sel-group sel-group-ungrouped wb-sel-group" data-gid=""></div>',
          );
          const $gh = parent$(
            `<div class="sel-group-header"><span class="sel-group-arrow" style="visibility:hidden;">▾</span><span class="sel-group-title">Chưa phân nhóm</span><div class="sel-group-actions"></div></div>`,
          );
          const $body = parent$('<div class="sel-group-body"></div>');
          ungrouped.forEach((name) => {
            const $row = makeRow(name);
            if ($row) $body.append($row);
          });
          $group.append($gh).append($body);
          $selList.append($group);
        }
      }

      const renderSelectedList = () => {
        if (selectedViewMode === "flat") renderSelectedFlat();
        else renderSelectedGrouped();
      };

      $content.append($topbar).append($panels);
      renderSelectedList();

      // Ràng buộc sự kiện: Chuyển tab
      $tabs.on("click", ".tab-btn", function () {
        const tab = parent$(this).data("tab");
        $tabs
          .find(".tab-btn")
          .removeClass("active")
          .attr("aria-selected", "false");
        parent$(this).addClass("active").attr("aria-selected", "true");
        if (tab === "all") {
          $allWrap.show();
          $selWrap.hide();
        } else {
          $allWrap.hide();
          $selWrap.show();
        }
        $content.scrollTop(0);
      });

      // Lọc tìm kiếm
      const applyFilter = () => {
        const kw = ($toolbar.find("#pt-wb-search").val() || "")
          .trim()
          .toLowerCase();
        $all.children(".wb-item").each((_, el) => {
          const name = el.getAttribute("data-name") || "";
          el.style.display = !kw || name.includes(kw) ? "" : "none";
        });
      };
      $toolbar.on("input", "#pt-wb-search", applyFilter);

      // Check thế giới thư
      $all.on("change", ".pt-wb-check", function () {
        const $lb = parent$(this).closest(".wb-item");
        const wbName = parent$(this).attr("data-wb-name");
        const checked = parent$(this).is(":checked");
        setWorldbookSelected(wbName, checked);
        $lb.toggleClass("is-selected", checked);
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      // Hủy thế giới thư
      $selList.on("click", ".pill-remove", function () {
        const wbName = parent$(this)
          .closest(".wb-sel-row")
          .attr("data-wb-name");
        setWorldbookSelected(wbName, false);
        $all
          .find(`.wb-item[data-wb-name="${wbName}"]`)
          .removeClass("is-selected")
          .find(".pt-wb-check")
          .prop("checked", false);
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      // Cài đặt nhóm
      $selList.on("click", ".pill-group", function (e) {
        e.stopPropagation();
        const wbName = parent$(this)
          .closest(".wb-sel-row")
          .attr("data-wb-name");
        const groups = getWorldbookGroups();
        const inNames =
          groups
            .filter((g) => (g.members || []).includes(wbName))
            .map((g) => g.name)
            .join("、") || "Không";
        const input = window.parent.prompt(
          `Thêm/xóa thế giới thư này khỏi nhóm (Nhóm hiện tại: ${inNames})\nQuy tắc:\n  - Bấm "OK" hoặc để trống: Xóa khỏi tất cả các nhóm\n  - Nhập tên nhóm đã có: Bật/tắt trong nhóm đó\n  - Nhập tên mới: Tạo nhóm và thêm vào`,
          "",
        );
        if (input === null) return;
        const name = (input || "").trim();
        if (!name) {
          groups.forEach((g) => {
            g.members = (g.members || []).filter((x) => x !== wbName);
          });
        } else {
          let g = groups.find((x) => x.name === name);
          if (!g) {
            g = {
              id:
                "wbg_" +
                Date.now().toString(36) +
                "_" +
                Math.floor(Math.random() * 9999),
              name,
              collapsed: false,
              members: [],
            };
            groups.push(g);
          }
          g.members = g.members || [];
          if (g.members.includes(wbName))
            g.members = g.members.filter((x) => x !== wbName);
          else g.members.push(wbName);
        }
        saveSettings();
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      // Thu gọn/mở rộng nhóm
      $selList.on("click", ".sel-group-arrow, .sel-group-title", function () {
        const $group = parent$(this).closest(".sel-group");
        const gid = $group.attr("data-gid") || "";
        if (!gid) return;
        const g = findWorldbookGroupById(gid);
        if (!g) return;
        g.collapsed = !g.collapsed;
        saveSettings();
        renderSelectedList();
      });

      // Đổi tên nhóm
      $selList.on("click", ".sel-group-rename", function (e) {
        e.stopPropagation();
        const gid = parent$(this).closest(".sel-group").attr("data-gid");
        const g = findWorldbookGroupById(gid);
        if (!g) return;
        const input = window.parent.prompt("Đổi tên nhóm", g.name || "");
        if (input === null) return;
        const name = (input || "").trim();
        if (!name) return;
        g.name = name;
        saveSettings();
        renderSelectedList();
      });

      // Xóa nhóm
      $selList.on("click", ".sel-group-delete", function (e) {
        e.stopPropagation();
        const gid = parent$(this).closest(".sel-group").attr("data-gid");
        settings.worldbookGroups = getWorldbookGroups().filter(
          (g) => g.id !== gid,
        );
        saveSettings();
        renderSelectedList();
      });

      // Nhóm mới
      $selWrap.on("click", ".sel-add-group-btn", function () {
        const input = window.parent.prompt("Tên nhóm mới");
        if (!input) return;
        const name = input.trim();
        if (!name) return;
        const groups = getWorldbookGroups();
        if (groups.some((g) => g.name === name)) return;
        groups.push({
          id:
            "wbg_" +
            Date.now().toString(36) +
            "_" +
            Math.floor(Math.random() * 9999),
          name,
          collapsed: false,
          members: [],
        });
        saveSettings();
        renderSelectedList();
      });

      // Mở rộng/Thu gọn tất cả
      $selWrap.on("click", ".sel-expand-groups-btn", function () {
        getWorldbookGroups().forEach((g) => (g.collapsed = false));
        saveSettings();
        renderSelectedList();
      });
      $selWrap.on("click", ".sel-collapse-groups-btn", function () {
        getWorldbookGroups().forEach((g) => (g.collapsed = true));
        saveSettings();
        renderSelectedList();
      });

      // Chuyển đổi chế độ xem
      $selToolbar.on("click", ".sel-view-mode-btn", function () {
        const $btn = parent$(this);
        const mode = $btn.data("mode");
        if (!mode || mode === selectedViewMode) return;
        selectedViewMode = mode;
        $selToolbar.find(".sel-view-mode-btn").removeClass("active");
        $btn.addClass("active");
        renderSelectedList();
      });

      // Sự kiện chuyển đổi chức năng
      $funcTabs.on("click", ".func-tab-btn", function () {
        const func = parent$(this).data("func");
        if (func === settings.currentFunctionTab) return;
        settings.currentFunctionTab = func;
        saveSettings();
        renderCurrentFunctionView();
      });
    }

    function populatePromptView(presetName) {
      const preset = getAllSillyTavernPresets()[presetName];
      const parent$ = window.parent.$;
      const $panel = parent$(`#${PANEL_ID}`);
      const $content = $panel.find(".panel-content");
      $panel.find(".footer-back-button").show();
      $content.empty();

      // Thẻ chuyển đổi chức năng
      const $funcTabs =
        parent$(`<div class="function-tabs" role="tablist" aria-label="Chuyển đổi chức năng">
            <button class="func-tab-btn active" data-func="preset" role="tab" aria-selected="true"><i class="fa-solid fa-list"></i> Mục Preset</button>
            <button class="func-tab-btn" data-func="worldbook" role="tab" aria-selected="false"><i class="fa-solid fa-book"></i> Thế giới thư</button>
        </div>`);

      if (!preset) {
        $content.append("<p>Không tìm thấy preset.</p>");
        return;
      }
      const idxMap = buildNameIndexMap(preset.prompts || []);
      ensureOrderArray(presetName);
      ensureGroupsCleanupForPreset(presetName);
      let selectedViewMode = "grouped";

      const $header = parent$('<div class="view-header"></div>').append(
        parent$("<h5></h5>").text(presetName),
      );
      const $tabs = parent$(
        `<div class="tabs" role="tablist" aria-label="Chuyển đổi chế độ xem mục"><button class="tab-btn active" data-tab="all" role="tab" aria-selected="true">Tất cả mục</button><button class="tab-btn" data-tab="selected" role="tab" aria-selected="false">Đã chọn</button></div>`,
      );
      const $toolbar = parent$(
        `<div class="prompt-toolbar"><input id="pt-search" type="text" placeholder="Tìm kiếm mục (từ khóa tên)" aria-label="Tìm kiếm mục" /></div>`,
      );
      const $topbarRow = parent$('<div class="prompt-view-topbar-row"></div>')
        .append($header)
        .append($tabs);
      const $topbar = parent$('<div class="prompt-view-topbar"></div>')
        .append($topbarRow)
        .append($toolbar);
      const $panels = parent$(
        `<div class="tabs-panels" data-preset="${presetName}"><div class="tab-panel tab-all"></div><div class="tab-panel tab-selected" style="display:none;"></div></div>`,
      );
      const $allWrap = $panels.find(".tab-all");
      const $selWrap = $panels.find(".tab-selected");

      const allItems = (preset.prompts || []).filter(
        (p) => p.name && !PLACEHOLDER_PROMPT_IDS.includes(p.id),
      );
      const $all = parent$('<div class="prompts-all"></div>');
      $allWrap.append($all);

      let iChunk = 0;
      const chunkSize = 20; // Giữ giá trị nhỏ để mượt trên di động

      function renderAllChunk() {
        // [Sửa lỗi 1] Chỉ kiểm tra xem vùng chứa có tồn tại không, bỏ qua document.contains để tránh việc bị xoá nhầm khi popup khởi tạo
        if (!$all || $all.length === 0) return;

        const end = Math.min(iChunk + chunkSize, allItems.length);

        for (; iChunk < end; iChunk++) {
          const p = allItems[iChunk];
          const uid = makeUid(p, idxMap);
          const checked = isSelected(presetName, p, idxMap);

          const $label = parent$('<label class="prompt-item"></label>')
            .attr("data-name", (p.name || "").toLowerCase())
            .attr("data-uid", uid)
            .attr("data-pid", p.id || "")
            .attr("title", p.name);

          if (checked) $label.addClass("is-selected");

          const $cb = parent$('<input type="checkbox" class="pt-check"/>')
            .prop("checked", checked)
            .attr("data-prompt-id", p.id || "")
            .attr("data-prompt-name", p.name || "")
            .attr("data-prompt-idx", parseNameUid(uid)?.idx || 1);

          const $span = parent$("<span></span>").text(p.name);

          $label.append($cb).append($span);

          // [Sửa lỗi 2] Dùng trực tiếp append, tương thích tốt nhất. Mỗi lần chỉ làm 20 cái, không bị đơ.
          $all.append($label);
        }

        if (iChunk < allItems.length) {
          // Giữ setTimeout độ trễ để cho đt có thời gian xử lý các sự kiện cuộn/cảm ứng
          setTimeout(renderAllChunk, 20);
        }
      }

      renderAllChunk();

      const $selToolbar = parent$(
        `<div class="sel-toolbar"><div class="sel-toolbar-left"><button type="button" class="sel-add-group-btn">Nhóm mới</button><button type="button" class="sel-expand-groups-btn">Mở rộng tất cả</button><button type="button" class="sel-collapse-groups-btn">Thu gọn tất cả</button></div><div class="sel-toolbar-right"><button type="button" class="sel-view-mode-btn active" data-mode="grouped">Theo nhóm</button><button type="button" class="sel-view-mode-btn" data-mode="flat">Tất cả danh sách</button></div></div>`,
      );
      const $selList = parent$(
        '<div class="sel-list" aria-label="Mục đã chọn, có thể kéo để sắp xếp"></div>',
      );
      $selWrap.append($selToolbar).append($selList);

      $selToolbar.on("click", ".sel-view-mode-btn", function () {
        const $btn = parent$(this);
        const mode = $btn.data("mode");
        if (!mode || mode === selectedViewMode) return;
        selectedViewMode = mode;
        $selToolbar.find(".sel-view-mode-btn").removeClass("active");
        $btn.addClass("active");
        renderSelectedList();
      });

      function renderSelectedFlat() {
        const m = getSelectedMap(presetName);
        const order = getSelectedOrder(presetName);
        $selList.empty();
        order.forEach((uid) => {
          const sel = m[uid];
          if (!sel) return;
          const labelText = sel.name || sel.id || uid;
          const idx = sel.idx;
          const display = sel.id
            ? labelText
            : idx
              ? `${labelText} #${idx}`
              : labelText;
          const row = parent$(
            `<div class="sel-row" data-uid="${uid}"><span class="drag-handle" title="Kéo để sắp xếp" aria-hidden="true">☰</span><span class="pill-text" title="${display}" style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${display}</span><button class="pill-group" title="Cài đặt nhóm" aria-label="Cài đặt nhóm"><i class="fa-solid fa-list-ul"></i></button><button class="pill-remove" title="Hủy mục này" aria-label="Hủy"><i class="fa-solid fa-times"></i></button></div>`,
          );
          $selList.append(row);
        });
      }

      function renderSelectedGrouped() {
        const m = getSelectedMap(presetName);
        const order = getSelectedOrder(presetName);
        const groups = getGroups(presetName);
        ensureGroupsCleanupForPreset(presetName);
        const groupedSet = new Set();
        const groupDisplay = new Map();
        groups.forEach((g) => {
          const list = (g.members || []).filter((uid) => !!m[uid]);
          if (list.length) {
            groupDisplay.set(g.id, list);
            list.forEach((uid) => groupedSet.add(uid));
          }
        });
        const ungrouped = [];
        order.forEach((uid) => {
          if (!m[uid]) return;
          if (!groupedSet.has(uid)) ungrouped.push(uid);
        });

        $selList.empty();
        const makeRow = (uid) => {
          const sel = m[uid];
          if (!sel) return null;
          const labelText = sel.name || sel.id || uid;
          const idx = sel.idx;
          const display = sel.id
            ? labelText
            : idx
              ? `${labelText} #${idx}`
              : labelText;
          return parent$(
            `<div class="sel-row" data-uid="${uid}"><span class="drag-handle" title="Kéo để sắp xếp" aria-hidden="true">☰</span><span class="pill-text" title="${display}" style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${display}</span><button class="pill-group" title="Cài đặt nhóm" aria-label="Cài đặt nhóm"><i class="fa-solid fa-list-ul"></i></button><button class="pill-remove" title="Hủy mục này" aria-label="Hủy"><i class="fa-solid fa-times"></i></button></div>`,
          );
        };

        groups.forEach((g) => {
          const uids = groupDisplay.get(g.id) || [];
          const $group = parent$('<div class="sel-group"></div>').attr(
            "data-gid",
            g.id,
          );
          if (g.collapsed) $group.addClass("collapsed");
          const $gh = parent$(
            `<div class="sel-group-header"><span class="sel-group-arrow" aria-hidden="true">▾</span><span class="sel-group-title"></span><div class="sel-group-actions"><button class="sel-group-drag" title="Kéo để sắp xếp nhóm" aria-label="Kéo để sắp xếp nhóm"><i class="fa-solid fa-bars"></i></button><button class="sel-group-add" title="Thêm mục vào nhóm này" aria-label="Thêm mục"><i class="fa-solid fa-plus"></i></button><button class="sel-group-rename" title="Đổi tên nhóm" aria-label="Đổi tên"><i class="fa-solid fa-pen"></i></button><button class="sel-group-delete" title="Xóa nhóm (không hủy chọn mục)" aria-label="Xóa nhóm"><i class="fa-solid fa-trash"></i></button></div></div>`,
          );
          $gh.find(".sel-group-title").text(g.name);
          const $body = parent$('<div class="sel-group-body"></div>');
          uids.forEach((uid) => {
            const $row = makeRow(uid);
            if ($row) $body.append($row);
          });
          $group.append($gh).append($body);
          $selList.append($group);
        });

        if (ungrouped.length) {
          const $group = parent$(
            '<div class="sel-group sel-group-ungrouped" data-gid=""></div>',
          );
          const $gh = parent$(
            `<div class="sel-group-header"><span class="sel-group-arrow" style="visibility:hidden;">▾</span><span class="sel-group-title">Chưa phân nhóm</span><div class="sel-group-actions"></div></div>`,
          );
          const $body = parent$('<div class="sel-group-body"></div>');
          ungrouped.forEach((uid) => {
            const $row = makeRow(uid);
            if ($row) $body.append($row);
          });
          $group.append($gh).append($body);
          $selList.append($group);
        }
      }

      const renderSelectedList = () => {
        if (selectedViewMode === "flat") renderSelectedFlat();
        else renderSelectedGrouped();
      };

      $tabs.on("click", ".tab-btn", function () {
        const tab = parent$(this).data("tab");
        $tabs
          .find(".tab-btn")
          .removeClass("active")
          .attr("aria-selected", "false");
        parent$(this).addClass("active").attr("aria-selected", "true");
        if (tab === "all") {
          $allWrap.show();
          $selWrap.hide();
        } else {
          $allWrap.hide();
          $selWrap.show();
        }
        $content.scrollTop(0);
      });

      const applyFilter = () => {
        const kw = ($toolbar.find("#pt-search").val() || "")
          .trim()
          .toLowerCase();
        $all.children(".prompt-item").each((_, el) => {
          const name = el.getAttribute("data-name") || "";
          el.style.display = !kw || name.includes(kw) ? "" : "none";
        });
      };
      $content.html("").append($funcTabs).append($topbar).append($panels);

      // Liên kết sự kiện chuyển đổi chức năng (Sau khi DOM được chèn)
      $funcTabs.on("click", ".func-tab-btn", function () {
        const func = parent$(this).data("func");
        if (func === "worldbook") {
          settings.currentFunctionTab = "worldbook";
          saveSettings();
          populateWorldbookMainMenu();
        }
      });
      $toolbar.on("input", "#pt-search", applyFilter);
      applyFilter();

      $all.on("change", ".pt-check", function () {
        const $lb = parent$(this).closest(".prompt-item");
        const p = {
          id: parent$(this).attr("data-prompt-id") || undefined,
          name: parent$(this).attr("data-prompt-name") || "",
        };
        const idx = parseInt(parent$(this).attr("data-prompt-idx"), 10) || 1;
        const fakeP = { id: p.id, name: p.name };
        const checked = parent$(this).is(":checked");
        setSelected(presetName, fakeP, idxMap, checked);
        $lb.toggleClass("is-selected", checked);
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selList.on("click", ".pill-remove", function () {
        const uid = parent$(this).closest(".sel-row").attr("data-uid");
        const m = getSelectedMap(presetName);
        const order = getSelectedOrder(presetName);
        delete m[uid];
        const i = order.indexOf(uid);
        if (i >= 0) order.splice(i, 1);
        const groups = getGroups(presetName);
        groups.forEach((g) => {
          g.members = (g.members || []).filter((x) => x !== uid);
        });
        saveSettings();
        $all
          .find(`.prompt-item[data-uid="${uid}"]`)
          .removeClass("is-selected")
          .find(".pt-check")
          .prop("checked", false);
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selList.on("click", ".pill-group", function (e) {
        e.stopPropagation();
        const uid = parent$(this).closest(".sel-row").attr("data-uid");
        const groups = getGroups(presetName);
        const inNames =
          groups
            .filter((g) => (g.members || []).includes(uid))
            .map((g) => g.name)
            .join("、") || "Không";
        const input = window.parent.prompt(
          `Thêm/xóa mục này khỏi nhóm (Nhóm hiện tại: ${inNames})\nQuy tắc:\n  - Bấm "OK" hoặc để trống: Xóa khỏi tất cả các nhóm\n  - Nhập tên nhóm đã có: Bật/tắt trong nhóm đó\n  - Nhập tên mới: Tạo nhóm và thêm vào`,
          "",
        );
        if (input === null) return;
        const name = (input || "").trim();
        if (!name) {
          groups.forEach((g) => {
            g.members = (g.members || []).filter((x) => x !== uid);
          });
        } else {
          let g = groups.find((x) => x.name === name);
          if (!g) {
            g = {
              id:
                "g_" +
                Date.now().toString(36) +
                "_" +
                Math.floor(Math.random() * 9999),
              name,
              collapsed: false,
              members: [],
            };
            groups.push(g);
          }
          g.members = g.members || [];
          if (g.members.includes(uid))
            g.members = g.members.filter((x) => x !== uid);
          else g.members.push(uid);
        }
        saveSettings();
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selList.on("click", ".sel-group-arrow, .sel-group-title", function () {
        const $group = parent$(this).closest(".sel-group");
        const gid = $group.attr("data-gid") || "";
        if (!gid) return;
        const g = findGroupById(presetName, gid);
        if (!g) return;
        g.collapsed = !g.collapsed;
        saveSettings();
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selList.on("click", ".sel-group-rename", function (e) {
        e.stopPropagation();
        const gid = parent$(this).closest(".sel-group").attr("data-gid");
        const g = findGroupById(presetName, gid);
        if (!g) return;
        const input = window.parent.prompt("Đổi tên nhóm", g.name || "");
        if (input === null) return;
        const name = (input || "").trim();
        if (!name) return;
        g.name = name;
        saveSettings();
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selList.on("click", ".sel-group-delete", function (e) {
        e.stopPropagation();
        const gid = parent$(this).closest(".sel-group").attr("data-gid");
        let groups = getGroups(presetName);
        groups = groups.filter((g) => g.id !== gid);
        settings.groupsByPreset[presetName] = groups;
        saveSettings();
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selWrap.on("click", ".sel-add-group-btn", function () {
        const input = window.parent.prompt("Tên nhóm mới");
        if (!input) return;
        const name = input.trim();
        if (!name) return;
        const groups = getGroups(presetName);
        if (groups.some((g) => g.name === name)) return;
        groups.push({
          id:
            "g_" +
            Date.now().toString(36) +
            "_" +
            Math.floor(Math.random() * 9999),
          name,
          collapsed: false,
          members: [],
        });
        saveSettings();
        renderSelectedList();
      });

      $selWrap.on("click", ".sel-expand-groups-btn", function () {
        const groups = getGroups(presetName);
        groups.forEach((g) => (g.collapsed = false));
        saveSettings();
        renderSelectedList();
        if (window.parent.$(`.${QUICK_OVERLAY_CLS}`).is(":visible")) {
          populateQuickMenu();
          fitQuickMenu();
          alignVisibleOverlays();
        }
      });

      $selList.on("click", ".sel-group-add", function (e) {
        e.stopPropagation();
        const gid = parent$(this).closest(".sel-group").attr("data-gid");
        if (!gid) return;
        const groups = getGroups(presetName);
        const g = groups.find((x) => x.id === gid);
        if (!g) return;
        const m = getSelectedMap(presetName);
        const order = getSelectedOrder(presetName);
        const membersSet = new Set(g.members || []);
        const candidates = [];
        order.forEach((uid) => {
          if (!m[uid]) return;
          if (membersSet.has(uid)) return;
          candidates.push({ uid, sel: m[uid] });
        });
        if (!candidates.length) {
          window.parent.toastr?.info?.(
            "Không có mục nào có thể thêm vào nhóm này (tất cả đã ở trong nhóm).",
          );
          return;
        }
        $selList.find(".sel-group-add-panel").remove();
        const $group = parent$(this).closest(".sel-group");
        const $body = $group.children(".sel-group-body").first();
        const $panel = parent$(
          `<div class="sel-group-add-panel"><div class="sel-group-add-title"></div><div class="sel-group-add-list"></div><div class="sel-group-add-actions"><button type="button" class="sel-group-add-confirm">Xác nhận</button><button type="button" class="sel-group-add-cancel">Hủy</button></div></div>`,
        );
        $panel.find(".sel-group-add-title").text(`Chọn mục để thêm vào “${g.name}”`);
        const $list = $panel.find(".sel-group-add-list");
        candidates.forEach(({ uid, sel }) => {
          const labelText = sel.name || sel.id || uid;
          const idx = sel.idx;
          const display = sel.id
            ? labelText
            : idx
              ? `${labelText} #${idx}`
              : labelText;
          const $item = parent$(
            `<label class="sel-group-add-item"><input type="checkbox" data-uid="${uid}"><span></span></label>`,
          );
          $item.find("span").text(display).attr("title", display);
          $list.append($item);
        });
        $panel.insertBefore($body);
      });

      $selList.on("click", ".sel-group-add-cancel", function (e) {
        e.stopPropagation();
        parent$(this).closest(".sel-group-add-panel").remove();
      });
      $selList.on("click", ".sel-group-add-confirm", function (e) {
        e.stopPropagation();
        const $panel = parent$(this).closest(".sel-group-add-panel");
        const $group = $panel.closest(".sel-group");
        const gid = $group.attr("data-gid");
        if (!gid) {
          $panel.remove();
          return;
        }
        const groups = getGroups(presetName);
        const g = groups.find((x) => x.id === gid);
        if (!g) {
          $panel.remove();
          return;
        }
        const members = new Set(g.members || []);
