          m = 6;
        if (rect.right > vw - m) ball.style.left = `${vw - m - rect.width}px`;
        if (rect.bottom > vh - m) ball.style.top = `${vh - m - rect.height}px`;
        if (rect.left < m) ball.style.left = `${m}px`;
        if (rect.top < m) ball.style.top = `${m}px`;
