    // ================= Lưu trữ IndexedDB =================
    const DB_NAME = 'ThMusicPlayerDB';
    const DB_VERSION = 1;
    let idbInstance = null;

    function initDB() {
        return new Promise((resolve, reject) => {
            const request = indexedDB.open(DB_NAME, DB_VERSION);
            request.onupgradeneeded = (e) => {
                const db = e.target.result;
                if (!db.objectStoreNames.contains('pinned_songs')) {
                    db.createObjectStore('pinned_songs', { keyPath: 'id' });
                }
                if (!db.objectStoreNames.contains('settings')) {
                    db.createObjectStore('settings', { keyPath: 'key' });
                }
            };
            request.onsuccess = (e) => {
                idbInstance = e.target.result;
                resolve();
            };
            request.onerror = (e) => {
                console.error('[MusicPlayer] Khởi tạo IndexedDB thất bại', e);
                reject(e);
            };
        });
    }

    function idbPut(storeName, data) {
        return new Promise((resolve) => {
            if (!idbInstance) return resolve();
            try {
                const tx = idbInstance.transaction(storeName, 'readwrite');
                const store = tx.objectStore(storeName);
                store.put(data);
                tx.oncomplete = () => resolve(true);
                tx.onerror = () => resolve(false);
            } catch (e) { resolve(false); }
        });
    }

    function idbGet(storeName, key) {
        return new Promise((resolve) => {
            if (!idbInstance) return resolve(null);
            try {
                const tx = idbInstance.transaction(storeName, 'readonly');
                const store = tx.objectStore(storeName);
                const req = store.get(key);
                req.onsuccess = () => resolve(req.result);
                req.onerror = () => resolve(null);
            } catch (e) { resolve(null); }
        });
    }

    function idbDelete(storeName, key) {
        return new Promise((resolve) => {
            if (!idbInstance) return resolve();
            try {
                const tx = idbInstance.transaction(storeName, 'readwrite');
                const store = tx.objectStore(storeName);
                store.delete(key);
                tx.oncomplete = () => resolve(true);
                tx.onerror = () => resolve(false);
            } catch (e) { resolve(false); }
        });
    }

    function idbGetAll(storeName) {
        return new Promise((resolve) => {
            if (!idbInstance) return resolve([]);
            try {
                const tx = idbInstance.transaction(storeName, 'readonly');
                const store = tx.objectStore(storeName);
                const req = store.getAll();
                req.onsuccess = () => resolve(req.result);
                req.onerror = () => resolve([]);
