            --th-mp-float-lrc-dark-shadow-2: var(--SmartThemeShadowColor, rgba(255, 255, 255, 0.5));
            --th-mp-lyrics-tint-color: var(--SmartThemeEmColor, #f28ea2);
        }

        /* Hiển thị lời bài hát nổi */
        .th-mp-floating-lyrics {
            position: absolute;
            /* Vị trí do class js điều khiển động */
            white-space: normal;
            width: max-content;
            max-width: 250px;
            line-height: 1.3;
            padding: 4px 12px;
            font-size: 14px;
            font-weight: bold;
            color: var(--th-mp-text);
            pointer-events: none;
            opacity: 0;
            transition: opacity 0.5s, top 0.3s, bottom 0.3s, left 0.3s, right 0.3s, color 0.3s, transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
            text-shadow: 0 0 4px var(--th-mp-accent-dark), 0 0 8px var(--th-mp-float-lrc-shadow);
            z-index: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 2px;
        }

        /* Biến thể vị trí lời bài hát nổi */
        .th-mp-floating-lyrics.pos-bottom {
            top: 65px; left: 50%; transform: translateX(-50%); text-align: center; transform-origin: top center;
        }
        .th-mp-floating-lyrics.pos-top {
            bottom: 65px; left: 50%; transform: translateX(-50%); text-align: center; transform-origin: bottom center;
        }
        .th-mp-floating-lyrics.pos-left {
            right: 65px; top: 50%; transform: translateY(-50%); align-items: flex-end; text-align: right; transform-origin: right center;
        }
        .th-mp-floating-lyrics.pos-right {
            left: 65px; top: 50%; transform: translateY(-50%); align-items: flex-start; text-align: left; transform-origin: left center;
        }

        /* Biến thể màu lời bài hát nổi */
        .th-mp-floating-lyrics.theme-light {
            color: var(--th-mp-float-lrc-light-text);
            text-shadow: 0 0 4px var(--th-mp-accent-dark), 0 0 8px var(--th-mp-float-lrc-shadow);
        }
        .th-mp-floating-lyrics.theme-dark {
            color: var(--th-mp-float-lrc-dark-text);
            text-shadow: 0 0 4px var(--th-mp-float-lrc-dark-shadow-1), 0 0 8px var(--th-mp-float-lrc-dark-shadow-2);
        }

        .th-mp-float-line-sub {
             font-size: 10px;
             opacity: 0.8;
             font-weight: normal;
        }

        .th-music-player.collapsed.lyrics-on .th-mp-floating-lyrics {
            opacity: 1;
        }

        /* Hiệu ứng chữ PV */
        .th-pv-char {
            display: inline-block;
            opacity: 0;
            vertical-align: text-bottom; /* Tối ưu căn lề cơ sở */
            animation: pv-char-in 0.6s cubic-bezier(0.22, 1, 0.36, 1) forwards;
            will-change: transform, opacity, filter;
        }

        @keyframes pv-char-in {
            0% {
                opacity: 0;
                transform: translate(var(--rx), var(--ry)) scale(1.2) rotate(var(--rr));
                filter: blur(8px);
            }
            100% {
                opacity: 1;
                transform: translate(0, 0) scale(1) rotate(0);
                filter: blur(0);
            }
        }

        /* CSS Bảng lời bài hát */
        .th-mp-lyrics-panel {
             position: absolute;
             top: 70px;
             left: 0;
             right: 0;
             height: 0; /* Mặc định thu gọn */
             background: var(--th-mp-bg);
             border-radius: 12px;
             padding: 0; /* Mặc định không có padding */
             display: flex;
             opacity: 0;
             visibility: hidden;
             flex-direction: column;
             align-items: center;
             overflow: hidden;
             box-shadow: none; /* Mặc định không bóng */
             z-index: 10001;
             text-align: center;
             transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
             transform: translateY(-20px) scale(0.95);
             pointer-events: none;
        }

        /* Thanh công cụ trên cùng của bảng lời bài hát */
        .th-mp-lyrics-toolbar {
            position: absolute;
            top: 5px;
            right: 5px;
            display: flex;
            gap: 6px; /* Giảm khoảng cách */
            opacity: 0.6;
            transition: opacity 0.2s;
            pointer-events: auto;
            z-index: 10003;
        }
        .th-mp-lyrics-toolbar:hover { opacity: 1; }

        .th-mp-tool-btn {
            background: none;
            border: none;
            color: var(--th-mp-subtext);
            cursor: pointer;
            padding: 3px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            pointer-events: auto;
        }
        .th-mp-tool-btn:hover {
            background: var(--th-mp-tool-btn-hover-bg);
            color: var(--th-mp-text);
            transform: scale(1.1);
        }
        .th-mp-tool-btn svg {
            width: 18px; height:18px;
            fill: none;
            stroke: currentColor;
            stroke-width: 2;
            stroke-linecap: round;
            stroke-linejoin: round;
        }

        .th-mp-lyrics-panel.show {
            opacity: 1;
            visibility: visible;
            transform: translateY(0) scale(1);
            pointer-events: auto;
            height: 140px; /* Chiều cao khi mở rộng */
            padding: 10px 0;
            box-shadow: 0 6px 20px var(--th-mp-shadow);
        }

        .th-mp-lyrics-content {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-size: 13px;
            color: var(--th-mp-subtext);
            /* Ẩn thanh cuộn */
            scrollbar-width: none;
            -ms-overflow-style: none;
            mask-image: linear-gradient(to bottom, transparent 0%, black 20%, black 80%, transparent 100%);
            -webkit-mask-image: linear-gradient(to bottom, transparent 0%, black 20%, black 80%, transparent 100%);
            padding: 0;
            position: relative;
        }

        .th-mp-lyrics-content::-webkit-scrollbar {
            display: none;
        }

        .th-mp-lyrics-line {
            padding: 6px 10px;
            transition: all 0.5s cubic-bezier(0.25, 0.46, 0.45, 0.94);
            line-height: 1.4;
            opacity: 0.5;
            transform: scale(0.95);
            filter: blur(0.5px);
        }

        .th-mp-lyrics-line.active {
            color: var(--th-mp-text);
            font-weight: bold;
            opacity: 1;
            transform: scale(1.05);
            filter: blur(0);
        }

        /* Easter Egg style */
        .th-mp-lyrics-tint {
             color: var(--th-mp-lyrics-tint-color) !important;
             text-shadow: 0 0 8px var(--th-mp-lyrics-tint-color) !important;
             font-weight: bold;
        }

        .th-mp-btn.active {
            color: var(--th-mp-accent);
            text-shadow: 0 0 5px var(--th-mp-accent);
        }

        .th-music-player {
            position: fixed;
            bottom: 100px;
            right: 50px;
            background: var(--th-mp-bg);
            box-shadow: 0 4px 15px var(--th-mp-shadow), inset 0 1px 3px var(--th-mp-panel-inner-shadow);
            z-index: 10000;
            color: var(--th-mp-text);
            font-family: 'Georgia', 'Segoe UI', serif;
            transition: width 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        height 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        padding 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        margin 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        background 0.4s, box-shadow 0.4s, border-radius 0.4s,
                        transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1),
                        opacity 0.4s;
            display: flex;
            align-items: center;
            overflow: visible;
            height: 60px;
            border-radius: 30px;
            padding: 0;
            user-select: none;
            box-sizing: border-box;
        }

        /* Trạng thái thu gọn (Hình tròn) */
        .th-music-player.collapsed {
            width: 60px;
            cursor: move;
        }

        /* Trạng thái thu nhỏ khi nhàn rỗi (Chỉ có tác dụng khi thu gọn) */
        .th-music-player.collapsed.mini {
            transform: scale(0.8);
            box-shadow: none;
        }
        .th-music-player.collapsed.mini:hover {
            transform: scale(1);
            opacity: 1;
            box-shadow: 0 4px 15px var(--th-mp-shadow);
        }

        /* Trạng thái mở rộng (Hình viên thuốc) */
        .th-music-player.expanded {
            width: 340px;
            padding-right: 24px;
        }

        .th-music-player.expand-left {
            flex-direction: row-reverse;
        }

        .th-music-player.expand-left.expanded {
            padding-right: 0;
            padding-left: 24px;
        }

        /* Khu vực ảnh bìa */
        .th-mp-cover-wrapper {
            width: 60px;
            height: 60px;
            flex-shrink: 0;
            position: relative;
            cursor: pointer;
            z-index: 2;
            -webkit-touch-callout: none;
            -webkit-user-select: none;
            user-select: none;
        }

        .th-mp-cover {
            width: 100%;
            height: 100%;
            border-radius: 50%;
            background: linear-gradient(135deg, var(--th-mp-accent-dark), var(--th-mp-accent-light));
            background-size: cover;
            background-position: center;
            border: none;
            box-shadow: 0 4px 12px var(--th-mp-shadow), inset 0 1px 4px var(--th-mp-cover-inner-shadow);
            display: flex;
            align-items: center;
            justify-content: center;
            transition: transform 0.3s ease;
        }

        .th-mp-cover svg {
            width: 24px;
            height: 24px;
            fill: var(--th-mp-cover-svg-fill);
            filter: drop-shadow(0 2px 4px var(--th-mp-cover-svg-shadow));
        }

        /* Hiệu ứng xoay */
        .th-music-player.playing .th-mp-cover {
            animation: spin 6s linear infinite;
        }

        @keyframes spin { 100% { transform: rotate(360deg); } }

        /* Nút chủ đề (Hiển thị khi mở rộng) */
        .th-mp-theme-float-btn {
            position: absolute;
            /* Nằm ở góc dưới bên trái ngoài viền hình tròn một chút */
            bottom: -5px;
            left: -5px;
            width: 24px;
            height: 24px;
            border-radius: 50%;
            background: var(--th-mp-bg);
            border: 1px solid var(--th-mp-border);
            color: var(--th-mp-subtext);
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            z-index: 10;
            opacity: 0;
            pointer-events: none;
            transform: scale(0.5);
            transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
            box-shadow: 0 2px 5px var(--th-mp-shadow);
        }

        /* Hiển thị nút chủ đề khi mở rộng và không ở chế độ mini */
        .th-music-player.expanded .th-mp-theme-float-btn {
            opacity: 1;
            pointer-events: auto;
            transform: scale(1);
        }

        .th-music-player.expand-left .th-mp-theme-float-btn {
            left: auto;
            right: -5px;
        }

        .th-mp-theme-float-btn:hover {
            color: var(--th-mp-accent);
            border-color: var(--th-mp-accent);
            transform: scale(1.1);
        }

        .th-mp-theme-float-btn svg {
            width: 14px;
            height: 14px;
            fill: currentColor;
        }

        /* Hiệu ứng lan tỏa sóng âm (Đa tầng) */
        .th-mp-wave {
            position: absolute;
            top: 50%; left: 50%;
            transform: translate(-50%, -50%);
            width: 100%; height: 100%;
            pointer-events: none;
            z-index: 1;
        }

        .th-mp-wave span {
            position: absolute;
            top: 50%; left: 50%;
            transform: translate(-50%, -50%);
            width: 100%; height: 100%;
            border-radius: 50%;
            border: 1px solid var(--th-mp-subtext);
            opacity: 0;
        }

        .th-music-player.collapsed.playing .th-mp-wave span {
            animation: ripple 3s infinite cubic-bezier(0.25, 0.46, 0.45, 0.94);
        }

        .th-music-player.collapsed.playing .th-mp-wave span:nth-child(1) { animation-delay: 0s; }
        .th-music-player.collapsed.playing .th-mp-wave span:nth-child(2) { animation-delay: 1s; }
        .th-music-player.collapsed.playing .th-mp-wave span:nth-child(3) { animation-delay: 2s; }

        @keyframes ripple {
            0% { width: 100%; height: 100%; opacity: 0.5; border-width: 1.5px; }
            100% { width: 220%; height: 220%; opacity: 0; border-width: 0px; }
        }

        /* Khu vực thông tin và điều khiển */
        .th-mp-body {
            flex: 1;
            display: flex;
            flex-direction: column;
            justify-content: center;
            overflow: hidden;
            margin-left: 16px;
            opacity: 1;
            transition: opacity 0.3s ease 0.1s;
        }

        .th-music-player.expand-left .th-mp-body {
            margin-left: 0;
            margin-right: 16px;
        }

        .th-music-player.collapsed .th-mp-body {
            opacity: 0;
            pointer-events: none;
            width: 0;
            margin: 0;
        }

        .th-mp-info {
            display: flex;
            flex-direction: row; /* Cùng một hàng */
            align-items: baseline;
            gap: 6px;
            margin-bottom: 6px;
            cursor: move;
            white-space: nowrap;
            overflow: hidden;
        }

        .th-mp-title {
            font-size: 14px;
            font-weight: bold;
            color: var(--th-mp-title-color);
            text-shadow: 0 1px 2px var(--th-mp-title-shadow);
        }

        .th-mp-artist {
            font-size: 11px;
            color: var(--th-mp-subtext);
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .th-mp-controls {
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 5px;
        }

        .th-mp-btn {
            background: transparent;
            border: none;
            color: var(--th-mp-subtext);
            cursor: pointer;
            padding: 5px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
        }

        .th-mp-btn:hover {
            color: var(--th-mp-btn-hover-text);
            background: var(--th-mp-btn-hover-bg);
            transform: scale(1.1);
        }

        .th-mp-btn svg {
            width: 18px;
            height: 18px;
            fill: currentColor;
            filter: drop-shadow(0 1px 2px var(--th-mp-btn-svg-shadow));
        }

        /* Bảng menu thả xuống của danh sách phát */
        .th-mp-playlist {
            position: absolute;
            top: 70px;
            left: 0;
            right: 0;
            background: var(--th-mp-bg);
            border-radius: 12px;
            padding: 0; /* Mặc định không có padding */
            display: flex;
            flex-direction: column;
            max-height: 0; /* Mặc định thu gọn */
            overflow: hidden;
            box-shadow: none; /* Mặc định không bóng */
            opacity: 0;
            visibility: hidden;
            transform: translateY(-10px);
            transition: all 0.3s ease;
            z-index: 10002; /* Cao hơn lời bài hát */
        }

        /* Khi bảng lời bài hát đang mở, danh sách phát dời xuống dưới */
        .th-music-player.lyrics-on .th-mp-playlist {
             top: 220px;
        }

        .th-mp-playlist.show {
            opacity: 1;
            visibility: visible;
            transform: translateY(0);
            max-height: 240px;
            padding: 8px 0;
            box-shadow: 0 6px 20px var(--th-mp-shadow);
        }

        .th-mp-playlist-input-area {
            display: flex;
            padding: 0 12px 8px 12px;
            gap: 8px;
            border-bottom: 1px solid var(--th-mp-input-area-border);
            margin-bottom: 4px;
            flex-shrink: 0;
        }

        .th-mp-add-input {
            flex: 1;
            background: var(--th-mp-input-bg);
            border: 1px solid var(--th-mp-input-border);
            border-radius: 6px;
            color: var(--th-mp-text);
            font-size: 11px;
            padding: 4px 6px;
            resize: none;
            outline: none;
            font-family: inherit;
        }
        .th-mp-add-input:textarea {
            box-shadow: none !important;
        }
        .th-mp-add-input::placeholder {
            color: var(--th-mp-subtext);
            opacity: 0.6;
        }
        .th-mp-add-input:focus {
            border-color: var(--th-mp-accent);
            background: var(--th-mp-input-focus-bg);
        }

        .th-mp-add-btn {
            background: var(--th-mp-accent);
            color: var(--th-mp-add-btn-text);
            border: none;
            border-radius: 6px;
            width: 30px;
            cursor: pointer;
            font-size: 16px;
            font-weight: bold;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: all 0.2s;
            padding: 0;
        }
        .th-mp-add-btn:hover {
            background: var(--th-mp-accent-light);
            transform: scale(1.05);
        }
        .th-mp-add-btn:active {
            transform: scale(0.95);
        }
        .th-mp-add-btn svg {
            width: 16px;
            height: 16px;
            fill: currentColor;
        }

        .th-mp-playlist-list {
            flex: 1;
            overflow-y: auto;
            display: flex;
            flex-direction: column;
        }

        .th-mp-playlist-item {
            padding: 6px 12px;
            font-size: 12px;
            color: var(--th-mp-subtext);
            cursor: pointer;
            transition: background 0.2s;
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 10px;
        }

        .th-mp-playlist-item:hover {
            background: var(--th-mp-list-hover);
            color: var(--th-mp-text);
        }

        .th-mp-playlist-item.active {
            color: var(--th-mp-accent);
            font-weight: bold;
            background: var(--th-mp-list-active);
        }

        .th-mp-playlist-info {
             display: flex;
             flex: 1;
             gap: 8px;
             align-items: baseline;
             overflow: hidden;
        }

        .th-mp-playlist-btn {
            width: 24px;
            height: 24px;
            display: flex;
            align-items: center;
            justify-content: center;
            border-radius: 4px;
            opacity: 0;
            transition: all 0.2s;
            flex-shrink: 0;
        }
        .th-mp-playlist-btn.pinned {
            opacity: 1 !important;
        }
        /* Thích ứng trên di động: Luôn hiển thị nút xóa trên màn hình cảm ứng hoặc nhỏ */
        @media (pointer: coarse), (max-width: 768px) {
            .th-mp-playlist-btn { opacity: 0.6; }
            /* Sửa lại vị trí mặc định trên di động */
            .th-music-player {
                top: 120px;
                right: 10px;
                bottom: auto;
            }
        }
        .th-mp-playlist-item:hover .th-mp-playlist-btn { opacity: 0.8; }
        .th-mp-playlist-btn:hover {
            opacity: 1 !important;
            background: var(--th-mp-del-btn-hover-bg);
            color: var(--th-mp-accent);
        }
        .th-mp-playlist-btn svg { width: 16px; height: 16px; fill: currentColor; }

        .th-mp-theme-upload {
            padding: 0 10px;
            font-size: 11px;
            color: var(--th-mp-subtext);
            cursor: pointer;
            text-align: center;
            white-space: nowrap;
            flex-shrink: 0;
            scroll-snap-align: center;
            transition: color 0.2s, text-shadow 0.2s;
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
            gap: 4px;
        }
        #th-mp-clear-cover {
            border-right: 1px solid var(--th-mp-theme-panel-border);
            margin-right: 5px;
        }
        .th-mp-theme-upload:hover {
            color: var(--th-mp-text);
        }
        .th-mp-theme-upload svg {
            width: 14px;
            height: 14px;
            fill: currentColor;
        }

        .th-mp-playlist-list::-webkit-scrollbar { width: 4px; }
        .th-mp-playlist-list::-webkit-scrollbar-thumb { background: var(--th-mp-accent-dark); border-radius: 2px; }

        /* Bảng chuyển đổi chủ đề dạng cuộn ngang */
        .th-mp-theme-panel {
            position: absolute;
            bottom: 70px;
            left: 50%;
            transform: translateX(-50%) translateY(10px) scale(0.9);
            background: var(--th-mp-bg);
            padding: 0 calc(50% - 25px);
            border-radius: 20px;
            display: flex;
            flex-direction: row;
            gap: 0px;
            opacity: 0;
            visibility: hidden;
            transition: opacity 0.3s, transform 0.3s, visibility 0.3s;
            box-shadow: none;
            z-index: 10005;
            pointer-events: none;
            width: 180px; /* Hẹp hơn */
            overflow-x: auto;
            overflow-y: hidden;
            height: 36px; /* Thấp hơn */
            scrollbar-width: none;
            -ms-overflow-style: none;
            align-items: center;
            justify-content: flex-start;
            backdrop-filter: blur(10px);
            border: 1px solid var(--th-mp-theme-panel-border);
            /* Chuyển mờ ở rìa nhẹ nhàng hơn */
            mask-image: linear-gradient(to right, transparent 0%, black 20%, black 80%, transparent 100%);
            -webkit-mask-image: linear-gradient(to right, transparent 0%, black 20%, black 80%, transparent 100%);
            scroll-snap-type: x mandatory;
            scroll-behavior: smooth;
            -webkit-overflow-scrolling: touch; /* Bật cuộn mượt (inertia) trên iOS */
        }
        .th-mp-theme-panel::-webkit-scrollbar {
            display: none;
        }
        .th-mp-theme-panel.show {
            opacity: 1;
            visibility: visible;
            transform: translateX(-50%) translateY(0) scale(1);
            pointer-events: auto;
            box-shadow: 0 4px 15px var(--th-mp-shadow);
        }
        .th-mp-theme-item {
            padding: 0;
            font-size: 11px; /* Font nhỏ hơn */
            color: var(--th-mp-subtext);
            cursor: pointer;
            text-align: center;
            white-space: nowrap;
            flex-shrink: 0;
            scroll-snap-align: center;
            opacity: 0.5;
            transform: scale(0.85);
            /* Bỏ transition của transform, dùng JS điều khiển mượt mà hơn */
            transition: color 0.2s, text-shadow 0.2s, opacity 0.1s linear;
            width: 50px;
            height: 100%;
            display: flex;
            justify-content: center;
            align-items: center;
        }
        .th-mp-theme-item:hover {
            color: var(--th-mp-text);
        }
        .th-mp-theme-item.active {
            color: var(--th-mp-accent) !important;
            font-weight: bold;
            text-shadow: 0 0 8px var(--th-mp-accent);
        }
    `;

