            // Khôi phục tọa độ an toàn, giới hạn trong màn hình
            const getSafePx = (val, max) => {
                if (!val || val === 'auto') return 'auto';
                let num = parseFloat(val);
                if (isNaN(num)) return 'auto';
                if (num < 0) num = 0;
                if (num > max - 60) num = max - 60;
                return `${num}px`;
            };

            const safeTop = getSafePx(savedPos.top, viewportHeight);

            if (safeTop !== 'auto') {
                player.style.top = safeTop;

                if (savedPos.right && savedPos.right !== 'auto') {
                    player.style.right = getSafePx(savedPos.right, viewportWidth);
                    player.style.left = 'auto';
                } else if (savedPos.left && savedPos.left !== 'auto') {
                    player.style.left = getSafePx(savedPos.left, viewportWidth);
                    player.style.right = 'auto';
