                    try {
                        await idbPut('settings', { key: 'custom_cover', data: file });
                        loadCustomCover();
                        if (typeof toastr !== 'undefined') toastr.success('Đã lưu ảnh bìa tùy chỉnh');
                    } catch (err) {
                        console.error('[MusicPlayer] Upload cover failed', err);
