            });
            clearBtn.addEventListener('pointerdown', (e) => e.stopPropagation());
        }

        // Ràng buộc nút công cụ trong bảng lời bài hát
        if(UI.lrcPosBtn) {
            UI.lrcPosBtn.addEventListener('click', toggleLyricsPosition);
            UI.lrcPosBtn.addEventListener('pointerdown', (e) => e.stopPropagation()); // Tránh kích hoạt kéo thả
        }
        if(UI.lrcThemeBtn) {
            UI.lrcThemeBtn.addEventListener('click', toggleLyricsTheme);
            UI.lrcThemeBtn.addEventListener('pointerdown', (e) => e.stopPropagation()); // Tránh kích hoạt kéo thả
        }

        // Ràng buộc sự kiện ô nhập
        if (UI.addBtn) {
            UI.addBtn.onclick = async (e) => {
                e.stopPropagation();
                if (!UI.addInput) return;
                const text = UI.addInput.value;
                if (!text.trim()) return;

                // Ưu tiên nhận diện link chia sẻ playlist của Netease
                const idMatch = text.match(/music\.163\.com.*?(?:id=)(\d+)/i);
                if (idMatch) {
                    const playlistId = idMatch[1];
                    UI.addBtn.disabled = true;
                    UI.addBtn.innerHTML = '...';

                    const success = await parseAndAddPlaylist(playlistId);

                    UI.addBtn.disabled = false;
                    UI.addBtn.innerHTML = '+';

                    if (success) {
                        UI.addInput.value = '';
                    }
                    return;
                }

                // Không khớp với playlist, thực hiện thêm từng dòng ban đầu
                const lines = text.split('\n');
                let addedCount = 0;
                let firstNewKey = null;

                lines.forEach(line => {
                    if (!line.trim()) return;
                    const parts = line.split('+');
                    if (parts.length >= 2) {
                        const title = parts[0].trim();
                        const artist = parts.slice(1).join('+').trim();
                        if (title && artist) {
                            const newKey = addMusicToPlaylist(title, artist, true);
                            if (newKey && !firstNewKey) firstNewKey = newKey;
                            addedCount++;
                        }
                    } else if (parts.length === 1 && parts[0].trim()) {
                        const title = parts[0].trim();
                        const newKey = addMusicToPlaylist(title, '', true);
                        if (newKey && !firstNewKey) firstNewKey = newKey;
                        addedCount++;
                    }
                });

                if (addedCount > 0) {
                    UI.addInput.value = '';
                    renderPlaylist();
                    if (typeof toastr !== 'undefined') toastr.success(`Đã thêm thành công ${addedCount} bài hát`);

                    if ((!bgmPlayer || bgmPlayer.paused) && isPlayerVisible && firstNewKey) {
                        playTrackByKey(firstNewKey);
                    }
                } else {
                    if (typeof toastr !== 'undefined') toastr.warning('Sai định dạng, vui lòng dùng "Tên bài hát+Ca sĩ"');
                }
            };
            UI.addBtn.onpointerdown = (e) => e.stopPropagation();
        }

        if (UI.exportBtn) {
            UI.exportBtn.onclick = async (e) => {
                e.stopPropagation();

