        });

        // Hỗ trợ cuộn ngang và hiệu ứng động cho thanh cuộn chủ đề
        if (UI.themePanel) {
            UI.themePanel.addEventListener('wheel', (e) => {
                e.preventDefault();
                UI.themePanel.scrollLeft += e.deltaY;
            }, { passive: false });

            UI.themePanel.addEventListener('pointerdown', (e) => e.stopPropagation());

            // Lắng nghe cuộn để cập nhật style (bao gồm cuộn chuột và chạm)
            let themeRafId = null;
            const requestThemeUpdate = () => {
                if (!themeRafId) {
                    themeRafId = requestAnimationFrame(() => {
                        updateThemeWheelStyles();
                        themeRafId = null;
                    });
                }
            };

            UI.themePanel.addEventListener('scroll', requestThemeUpdate, { passive: true });
            UI.themePanel.addEventListener('touchmove', requestThemeUpdate, { passive: true });
        }

        // Cảm biến nhàn rỗi
        if (UI.player) {
            UI.player.addEventListener('mouseenter', resetIdleTimer);
            UI.player.addEventListener('mousemove', resetIdleTimer);
            UI.player.addEventListener('mouseleave', startIdleTimer);
        }

        // Logic kéo thả
        if(UI.player) makeDraggable(UI.player);

        // Trạng thái khởi tạo
        syncUIWithSettings();
        renderPlaylist();
        startIdleTimer();

        // Nhấp ra ngoài để tự động thu gọn
        const onDocClick = (e) => {
            if (!doc.body.contains(UI.player)) {
                doc.removeEventListener('click', onDocClick);
                return;
            }

            if (UI.player && !UI.player.classList.contains('collapsed') && !e.composedPath().includes(UI.player)) {
                toggleCollapse();
            }
        };
        // Lưu lại tham chiếu sự kiện để dễ dàng gỡ bỏ
        if(UI.player) UI.player._onDocClick = onDocClick;
        setTimeout(() => doc.addEventListener('click', onDocClick), 0);

        // Chỉnh lại hướng mở rộng và định vị ban đầu
        setTimeout(() => {
            updateExpandDirection(true);
        }, 50);

        // Lắng nghe thay đổi kích thước cửa sổ, tránh bị bay mất
        UI._onResize = () => { if (UI.player) updateExpandDirection(true); };
        window.addEventListener('resize', UI._onResize);
    }

    // Cập nhật hướng mở rộng và cơ sở định vị
    function updateExpandDirection(forceRecalculate = false) {
        if (!UI.player) return;

        if (!forceRecalculate && UI.player.getAttribute('data-dragging') === 'true') {
            if (lyricsConfig.position === 'left') {
                UI.player.classList.add('expand-left');
            } else {
                UI.player.classList.remove('expand-left');
            }
            return;
        }

        const viewportWidth = doc.documentElement.clientWidth || window.parent.innerWidth || window.innerWidth;
        const viewportHeight = doc.documentElement.clientHeight || window.parent.innerHeight || window.innerHeight;

        const rect = UI.player.getBoundingClientRect();
        let currentLeft = rect.left;
        let currentTop = rect.top;
        const currentWidth = rect.width;

        const shouldExpandLeft = (lyricsConfig.position === 'left');

        // Chiều rộng tối đa mong đợi
        const maxExpectedWidth = !isCollapsed ? 340 : 60;

        // Cơ chế chống bay mất: đảm bảo nút trên cùng (60px) luôn nằm trong màn hình
        currentTop = Math.max(0, Math.min(currentTop, viewportHeight - 60));

        if (shouldExpandLeft) {
            UI.player.classList.add('expand-left');

            // Ở chế độ mở sang trái: lấy lề phải làm mốc (thuộc tính right)
            let currentRight = viewportWidth - (currentLeft + currentWidth);

            // Chống tràn lề phải
            if (currentRight < 0) currentRight = 0;
            // Chống tràn lề trái
            if (currentRight > viewportWidth - 60) currentRight = viewportWidth - 60;

            // Khi mở, nếu bên trái bị kẹt màn hình, đẩy toàn bộ sang phải
            if (forceRecalculate && (currentRight + maxExpectedWidth > viewportWidth)) {
                currentRight = Math.max(0, viewportWidth - maxExpectedWidth);
            }

            UI.player.style.right = `${currentRight}px`;
            UI.player.style.left = 'auto';

        } else {
            UI.player.classList.remove('expand-left');

            // Ở chế độ mở sang phải: lấy lề trái làm mốc (thuộc tính left)
            let calculatedLeft = currentLeft;

            // Chống tràn lề trái
            if (calculatedLeft < 0) calculatedLeft = 0;
            // Chống tràn lề phải
            if (calculatedLeft > viewportWidth - 60) calculatedLeft = viewportWidth - 60;

            // Khi mở, nếu bên phải bị kẹt màn hình, đẩy toàn bộ sang trái
            if (forceRecalculate && (calculatedLeft + maxExpectedWidth > viewportWidth)) {
                calculatedLeft = Math.max(0, viewportWidth - maxExpectedWidth);
            }

            UI.player.style.left = `${calculatedLeft}px`;
            UI.player.style.right = 'auto';
        }

        // Luôn định vị bằng top thay vì bottom để tránh giật khi thanh dưới cùng của trình duyệt ẩn/hiện
        UI.player.style.top = `${currentTop}px`;
        UI.player.style.bottom = 'auto';

        setScriptVar('pos', {
            left: UI.player.style.left,
            right: UI.player.style.right,
            top: UI.player.style.top
        });
    }

    // Thu nhỏ tự động khi không dùng
    function startIdleTimer() {
        clearTimeout(idleTimer);
        if (!UI.player) return;

        idleTimer = setTimeout(() => {
            if (isCollapsed && !isLyricsEnabled) {
                UI.player.classList.add('mini');
            }
        }, 6000);
    }

    function resetIdleTimer() {
        clearTimeout(idleTimer);
        if (UI.player) UI.player.classList.remove('mini');
    }

    // Logic Kéo thả
    function makeDraggable(element) {
        let isDragging = false;
        let startX, startY, initialLeft, initialTop;
        let startTarget = null;
        let currentX, currentY;
        let rafId = null;

        const updatePosition = () => {
            if (!isDragging) return;
            const dx = currentX - startX;
            const dy = currentY - startY;

            if (Math.abs(dx) > 5 || Math.abs(dy) > 5) {
                element.setAttribute('data-dragging', 'true');
            }

            element.style.left = `${initialLeft + dx}px`;
            element.style.top = `${initialTop + dy}px`;

            rafId = null;
        };

        const onPointerDown = (e) => {
            if (e.target.closest('.th-mp-btn') || e.target.closest('.th-mp-playlist')) return;
            if (e.button !== 0) return;

            isDragging = true;
            startTarget = e.target;
            element.setAttribute('data-dragging', 'false');
            element.setPointerCapture(e.pointerId);

            const rect = element.getBoundingClientRect();
            initialLeft = rect.left;
            initialTop = rect.top;

            startX = e.clientX;
            startY = e.clientY;

            // Khởi tạo currentX/Y để tránh undefined
            currentX = startX;
            currentY = startY;

            element.style.bottom = 'auto';
            element.style.right = 'auto';
            element.style.left = `${initialLeft}px`;
            element.style.top = `${initialTop}px`;

            // Gợi ý trình duyệt tối ưu will-change
            element.style.willChange = 'left, top';

            element.addEventListener('pointermove', onPointerMove);
            element.addEventListener('pointerup', onPointerUp);
            element.addEventListener('pointercancel', onPointerUp);
        };

        const onPointerMove = (e) => {
            if (!isDragging) return;
            e.preventDefault(); // Tránh kích hoạt cuộn hoặc các hành vi mặc định

            currentX = e.clientX;
            currentY = e.clientY;

            if (!rafId) {
                rafId = requestAnimationFrame(updatePosition);
            }
        };

        const onPointerUp = (e) => {
            isDragging = false;

            if (rafId) {
                cancelAnimationFrame(rafId);
                rafId = null;
                // Đảm bảo lần cập nhật vị trí cuối cùng được chạy
                updatePosition();
            }

            element.releasePointerCapture(e.pointerId);
            element.removeEventListener('pointermove', onPointerMove);
            element.removeEventListener('pointerup', onPointerUp);
            element.removeEventListener('pointercancel', onPointerUp);

            // Bỏ will-change
            element.style.willChange = 'auto';

            // Quyết định dùng left hay right tùy theo hướng
            const viewportWidth = doc.documentElement.clientWidth || window.parent.innerWidth;
            const viewportHeight = doc.documentElement.clientHeight || window.parent.innerHeight;
            const finalRect = element.getBoundingClientRect();

            let finalLeft = finalRect.left;
            let finalRight = viewportWidth - finalRect.right;
            let finalTop = finalRect.top;

            // Không cho rớt khỏi màn hình theo chiều dọc
            if (finalTop < 0) {
                 finalTop = 0;
            } else if (finalTop > viewportHeight - 60) {
                 finalTop = Math.max(0, viewportHeight - 60);
            }

            let shouldExpandLeft = (lyricsConfig.position === 'left');

            if (shouldExpandLeft) {
                element.classList.add('expand-left');
                // Ngăn lọt màn hình theo chiều ngang
                if (finalRight < 0) finalRight = 0;
                if (finalRight > viewportWidth - 60) finalRight = viewportWidth - 60;

                element.style.right = `${finalRight}px`;
                element.style.left = 'auto';
                element.style.top = `${finalTop}px`;
            } else {
                element.classList.remove('expand-left');
                // Ngăn lọt màn hình
                if (finalLeft < 0) finalLeft = 0;
                if (finalLeft > viewportWidth - 60) finalLeft = viewportWidth - 60;

                element.style.left = `${finalLeft}px`;
                element.style.right = 'auto';
                element.style.top = `${finalTop}px`;
            }

            setScriptVar('pos', {
                left: element.style.left,
                right: element.style.right,
                top: element.style.top
            });

            if (element.getAttribute('data-dragging') === 'false') {
                if (startTarget && startTarget.closest('#th-mp-toggle-collapse')) {
                    toggleCollapse();
                }
            }
            element.removeAttribute('data-dragging');
        };

        element.addEventListener('pointerdown', onPointerDown);
    }

    // Thu gọn/Mở rộng
    function toggleCollapse() {
        if (!UI.player) return;

        // Luôn đóng bảng chủ đề trước khi làm gì khác
        if(UI.themePanel) UI.themePanel.classList.remove('show');

        isCollapsed = !isCollapsed;

        if (isCollapsed) {
            UI.player.classList.add('collapsed');
            UI.player.classList.remove('expanded');

            // Đóng tất cả các bảng khi thu gọn
            if (UI.lyricsPanel) UI.lyricsPanel.classList.remove('show');
            if (UI.playlistPanel) UI.playlistPanel.classList.remove('show');

            startIdleTimer();
        } else {
            UI.player.classList.remove('collapsed');
            UI.player.classList.add('expanded');
            UI.player.classList.remove('mini');
            clearTimeout(idleTimer);

            if (isLyricsEnabled && UI.lyricsPanel) {
                UI.lyricsPanel.classList.add('show');
            }
        }
    }

    // Cuộn an toàn trong container
    function scrollToThemeItem(item) {
        if (!UI.themePanel || !item) return;
        const panelWidth = UI.themePanel.offsetWidth || 180;
        const itemLeft = item.offsetLeft;
        const itemWidth = item.offsetWidth || 50;
        const targetScrollLeft = itemLeft - (panelWidth / 2) + (itemWidth / 2);
        UI.themePanel.scrollTo({ left: targetScrollLeft, behavior: 'smooth' });
    }

    function scrollToLyricsLine(line) {
        if (!UI.lyricsContent || !line) return;
        const containerHeight = UI.lyricsContent.offsetHeight || 120;
        const lineTop = line.offsetTop;
        const lineHeight = line.offsetHeight || 20;
        const targetScrollTop = lineTop - (containerHeight / 2) + (lineHeight / 2);
        UI.lyricsContent.scrollTo({ top: targetScrollTop, behavior: 'smooth' });
    }

    // Cập nhật hiệu ứng cho bánh xe chọn chủ đề
    function updateThemeWheelStyles() {
        if (!UI.themePanel || !UI.themeItems || UI.themeItems.length === 0) return;

        const panelWidth = UI.themePanel.offsetWidth || 180;
        const scrollLeft = UI.themePanel.scrollLeft;
        const center = scrollLeft + panelWidth / 2;

        // Đọc 1 lần
        const centers = UI.themeItems.map(item => item.offsetLeft + (item.offsetWidth || 50) / 2);

        UI.themeItems.forEach((item, index) => {
            const itemCenter = centers[index];
            const dist = Math.abs(center - itemCenter);
            const maxDist = panelWidth / 2; // Khoảng cách ảnh hưởng tối đa

            let scale = 0.8;
            let opacity = 0.4;

            if (dist < maxDist) {
                const ratio = 1 - (dist / maxDist);
                const smoothRatio = (1 - Math.cos(ratio * Math.PI / 2));
                scale = 0.8 + (0.35 * smoothRatio);
                opacity = 0.4 + (0.6 * smoothRatio);
            }

            item.style.transform = `scale3d(${scale}, ${scale}, 1)`;
            item.style.opacity = opacity;
        });
    }

    function toggleThemePanel() {
        if (UI.themePanel) {
            UI.themePanel.classList.toggle('show');
            // Đặt lại thời gian nhàn rỗi nếu mở bảng
            if (UI.themePanel.classList.contains('show')) {
                resetIdleTimer();
                // Cuộn tự động tới chủ đề hiện tại
                const active = UI.themePanel.querySelector('.active');
                if(active) {
                    // Cập nhật style ngay lập tức 1 lần
                    setTimeout(() => {
                        scrollToThemeItem(active);
                        // Cập nhật lần nữa sau khi đã cuộn
                        setTimeout(updateThemeWheelStyles, 350);
                    }, 50);
                }
                updateThemeWheelStyles();
            } else {
                startIdleTimer();
            }
        }
    }

    function switchTheme(theme) {
        currentTheme = theme;
        setScriptVar('theme', theme);

        if (UI.player) {
            UI.player.classList.remove('theme-blue', 'theme-daydream', 'theme-crimson', 'theme-qingdai', 'theme-xuansha', 'theme-dihua', 'theme-centuryend', 'theme-adaptive');
            if (theme === 'blue') {
                UI.player.classList.add('theme-blue');
            } else if (theme === 'daydream') {
                UI.player.classList.add('theme-daydream');
            } else if (theme === 'crimson') {
                UI.player.classList.add('theme-crimson');
            } else if (theme === 'qingdai') {
                UI.player.classList.add('theme-qingdai');
            } else if (theme === 'xuansha') {
                UI.player.classList.add('theme-xuansha');
            } else if (theme === 'dihua') {
                UI.player.classList.add('theme-dihua');
            } else if (theme === 'centuryend') {
                UI.player.classList.add('theme-centuryend');
            } else if (theme === 'adaptive') {
                UI.player.classList.add('theme-adaptive');
            }
        }

        if (UI.themePanel && UI.themeItems) {
            UI.themeItems.forEach(item => {
                if(item.dataset.theme === theme) {
