  <div class="hc-shell" :data-open="panelState.open ? 'true' : 'false'">
    <div class="hc-backdrop" @click="close"></div>

    <section v-if="block" class="hc-dialog" role="dialog" aria-modal="true" aria-label="Bảng đoạn bình tiểu thuyết">
      <header class="hc-head">
        <div class="hc-titlebar">
          <span class="hc-title">Đoạn bình</span>
          <button class="hc-close" type="button" aria-label="Đóng đoạn bình" @click="close">×</button>
        </div>

        <div class="hc-summary">
          <div class="hc-emoji" :class="{ 'hc-emoji--kaomoji': isKaomoji(block.emoji) }" aria-hidden="true">
            {{ block.emoji }}
          </div>
          <div class="hc-summary-copy">
            <p class="hc-count">Tất cả đoạn bình {{ formatCount(block.count) }}</p>
            <p class="hc-subline">Hiển thị {{ block.comments.length }} đoạn bình chọn lọc</p>
          </div>
        </div>

        <div class="hc-tags">
          <span v-for="tag in block.tags" :key="tag" class="hc-tag">{{ tag }}</span>
        </div>
      </header>

      <div class="hc-list">
        <article v-for="entry in block.comments" :key="`${entry.user}-${entry.text}`" class="hc-comment">
          <div
            class="hc-avatar"
            :style="{
              backgroundColor: getAvatarPalette(entry.user).bg,
              color: getAvatarPalette(entry.user).fg,
            }"
          >
            {{ getAvatarText(entry.user) }}
          </div>

          <div class="hc-comment-copy">
            <p class="hc-user">{{ entry.user }}</p>
            <p class="hc-text">{{ entry.text }}</p>
          </div>
        </article>
      </div>
    </section>
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue';
import { panelState } from './panel-state';

const props = defineProps<{
  close: () => void;
}>();

const block = computed(() => panelState.block);

const AVATAR_PALETTES = [
  { bg: '#ead7c6', fg: '#63381d' },
  { bg: '#d8e3d0', fg: '#31513a' },
  { bg: '#d8dde8', fg: '#334b69' },
  { bg: '#e7d5e3', fg: '#62415f' },
  { bg: '#eadcb6', fg: '#6f4c12' },
];

function hashString(text: string): number {
  let hash = 0;
  for (const char of text) {
    hash = (hash * 131 + char.codePointAt(0)!) >>> 0;
  }
  return hash;
}

function getAvatarPalette(seed: string) {
  return AVATAR_PALETTES[hashString(seed) % AVATAR_PALETTES.length];
}

function getAvatarText(name: string): string {
  return Array.from(name.trim())[0] ?? 'Bình';
}

function formatCount(count: number): string {
  return Math.max(0, count).toLocaleString('zh-CN');
}

function isKaomoji(value: string): boolean {
  const trimmed = value.trim();
  return Array.from(trimmed).length > 2 || /[()（）[\]【】\\/|^_><~=;:・･｜]/.test(trimmed);
}

function close(): void {
  props.close();
}
</script>

