  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.22em;
  min-width: 2.05em;
  margin-left: 0.3em;
  padding: 0.06em 0.52em;
  border: 1px solid #d9c8ac;
  border-radius: 0.46em;
  background: #f7efdf;
  color: #9f2f23;
  font-size: 0.82em;
  line-height: 1.15;
  vertical-align: 0.06em;
  box-shadow: 0 1px 0 rgba(86, 58, 21, 0.08);
  cursor: pointer;
  appearance: none;
  pointer-events: auto;
  user-select: none;
  -webkit-user-select: none;
  -webkit-touch-callout: none;
  -webkit-tap-highlight-color: transparent;
  touch-action: manipulation;
  transition:
    background-color 160ms ease,
    border-color 160ms ease,
    color 160ms ease;
}

.novel-hc-badge::after {
  content: '';
  position: absolute;
  left: 0.52em;
  bottom: -0.25em;
  width: 0.48em;
  height: 0.48em;
  border-right: 1px solid #d9c8ac;
  border-bottom: 1px solid #d9c8ac;
  background: #f7efdf;
  transform: rotate(42deg);
  pointer-events: none;
}

.novel-hc-badge:hover,
.novel-hc-badge:focus-visible,
.novel-hc-badge--active {
  border-color: #d58a2c;
  background: #fff4df;
  color: #c05410;
  outline: none;
}

.novel-hc-badge__emoji,
.novel-hc-badge__count {
  position: relative;
  z-index: 1;
  white-space: nowrap;
}

.novel-hc-badge__emoji {
  font-size: 0.98em;
  line-height: 1;
}

.novel-hc-badge__count {
  font-weight: 700;
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.01em;
}

body.novel-hc-body-lock {
  overflow: hidden !important;
}

@media (hover: hover) {
  .novel-hc-badge:hover {
    border-color: #d58a2c;
    background: #fff4df;
    color: #c05410;
  }
}

@media (max-width: 979px), (hover: none), (pointer: coarse) {
  .novel-hc-badge {
    min-width: 1.92em;
    margin-left: 0.24em;
    padding: 0.05em 0.48em;
    font-size: 0.78em;
    gap: 0.18em;
  }

  .novel-hc-badge::after {
    left: 0.45em;
  }
}
