    position: absolute;
    width: ${CONFIG.SUB_SIZE}px;
    height: ${CONFIG.SUB_SIZE}px;
    border-radius: 50%;
    box-shadow: 0 3px 15px rgba(0,0,0,0.25);
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    user-select: none;
