    animation: fmmCollapseBall ${CONFIG.ANIMATION_DURATION}ms ease-in forwards;
}
</style>
        `;

        parentDocument.head.insertAdjacentHTML('beforeend', styles);
    }

    // ============ Tạo bóng nổi chính ============
    function createMainFab() {
        const fab = parentDocument.createElement('div');
        fab.className = 'fmm-main-fab';
        fab.innerHTML = `<div class="icon">${ICONS.menu}</div>`;

        // Cài đặt vị trí ban đầu
        fab.style.top = state.position.top + 'px';
        fab.style.left = state.position.left + 'px';

        parentDocument.body.appendChild(fab);
        state.elements.main = fab;

        // Ràng buộc sự kiện
        bindMainFabEvents(fab);

        return fab;
    }

    // ============ Tạo container bóng phụ ============
    function createSubContainer() {
        const container = parentDocument.createElement('div');
        container.className = 'fmm-sub-container';
        parentDocument.body.appendChild(container);
        state.elements.subContainer = container;
        return container;
    }

    // ============ Cập nhật vị trí container bóng phụ ============
    function updateSubContainerPosition() {
        if (!state.elements.main || !state.elements.subContainer) return;

        const container = state.elements.subContainer;

        // Vị trí container bóng phụ căn chỉnh với bóng chính
        container.style.top = state.position.top + 'px';
        container.style.left = state.position.left + 'px';
        container.style.width = CONFIG.SUB_SIZE + 'px';
        container.style.height = (state.buttons.length * CONFIG.SUB_SPACING) + 'px';
    }

    // ============ Tạo bóng nổi phụ ============
    function createSubFab(config, index) {
        const fab = parentDocument.createElement('div');
        fab.className = 'fmm-sub-fab';
        fab.style.background = config.color || 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)';

        // Cài đặt nội dung biểu tượng
        if (typeof config.icon === 'string') {
            fab.innerHTML = config.icon;
        } else {
            fab.textContent = config.icon || '●';
        }

        // Cài đặt độ lệch vị trí
        const offset = -(index + 1) * CONFIG.SUB_SPACING;
        fab.style.setProperty('--offset', offset + 'px');
        fab.style.top = '0px';
        fab.style.left = '4px'; // Căn giữa ((56-48)/2 = 4px)

        // Ràng buộc sự kiện click
        fab.addEventListener('click', function(e) {
            e.stopPropagation();
            if (config.onClick && typeof config.onClick === 'function') {
                config.onClick();
            }
        });

        state.elements.subContainer.appendChild(fab);
        state.elements.subs.push(fab);

        return fab;
    }

    // ============ Render tất cả bóng phụ ============
    function renderSubFabs() {
        // Xóa bóng phụ hiện tại
        state.elements.subs.forEach(fab => fab.remove());
        state.elements.subs = [];

        // Tạo bóng phụ mới
        state.buttons.forEach((config, index) => {
            createSubFab(config, index);
        });

        updateSubContainerPosition();
    }

    // ============ Mở menu ============
    function expand() {
        if (state.isExpanded) return;
        state.isExpanded = true;

        // Cập nhật biểu tượng bóng chính
        const icon = state.elements.main.querySelector('.icon');
        icon.innerHTML = ICONS.chevronDown;
        state.elements.main.classList.add('expanded');

        // Mở bóng phụ
        state.elements.subs.forEach((fab, index) => {
            fab.classList.remove('collapsing');
            fab.classList.add('expanding');

            // Hiển thị có độ trễ, tạo hiệu ứng xếp tầng
            setTimeout(() => {
                fab.style.opacity = '1';
                fab.style.transform = `translateY(${-(index + 1) * CONFIG.SUB_SPACING}px) scale(1)`;
            }, index * 50);
        });
    }

    // ============ Đóng menu ============
    function collapse() {
        if (!state.isExpanded) return;
        state.isExpanded = false;

        // Cập nhật biểu tượng bóng chính
        const icon = state.elements.main.querySelector('.icon');
        icon.innerHTML = ICONS.menu;
        state.elements.main.classList.remove('expanded');

        // Đóng bóng phụ
        state.elements.subs.forEach((fab, index) => {
            fab.classList.remove('expanding');
            fab.classList.add('collapsing');

            setTimeout(() => {
                fab.style.opacity = '0';
                fab.style.transform = 'translateY(0) scale(0)';
            }, index * 30);
        });
    }

    // ============ Chuyển đổi mở/đóng ============
    function toggle() {
        if (state.isExpanded) {
            collapse();
        } else {
            expand();
        }
    }

    // ============ Sự kiện kéo thả bóng chính ============
    function bindMainFabEvents(fab) {
        let rafId = null;

        function handleStart(e) {
            const touch = e.touches ? e.touches[0] : e;
            state.isDragging = true;
            state.hasMoved = false;
            state.dragData.startX = touch.clientX;
            state.dragData.startY = touch.clientY;

            const rect = fab.getBoundingClientRect();
            state.dragData.initialTop = rect.top;
            state.dragData.initialLeft = rect.left;

            fab.classList.add('dragging');
            e.preventDefault();
        }

        function handleMove(e) {
            if (!state.isDragging) return;

            const touch = e.touches ? e.touches[0] : e;
            const deltaX = touch.clientX - state.dragData.startX;
            const deltaY = touch.clientY - state.dragData.startY;

            // Kiểm tra xem có di chuyển không
            if (Math.abs(deltaX) > CONFIG.DRAG_THRESHOLD || Math.abs(deltaY) > CONFIG.DRAG_THRESHOLD) {
                state.hasMoved = true;
            }

            // Sử dụng RAF tối ưu hiệu suất
            if (rafId) cancelAnimationFrame(rafId);
            rafId = requestAnimationFrame(() => {
                const newLeft = Math.max(0, Math.min(
                    state.dragData.initialLeft + deltaX,
                    window.parent.innerWidth - CONFIG.MAIN_SIZE
                ));
                const newTop = Math.max(0, Math.min(
                    state.dragData.initialTop + deltaY,
                    window.parent.innerHeight - CONFIG.MAIN_SIZE
                ));

                state.position.left = newLeft;
                state.position.top = newTop;

                fab.style.left = newLeft + 'px';
                fab.style.top = newTop + 'px';

                // Cập nhật vị trí container bóng phụ
                updateSubContainerPosition();

                rafId = null;
            });

            e.preventDefault();
        }

        function handleEnd(e) {
            if (!state.isDragging) return;
            state.isDragging = false;
            fab.classList.remove('dragging');

            // Lưu vị trí
            savePosition();

            // Nếu không di chuyển, coi như là click
            if (!state.hasMoved) {
                toggle();
            }

            state.hasMoved = false;
            e.preventDefault();
        }

        // Sự kiện chuột
        fab.addEventListener('mousedown', handleStart);
        parentDocument.addEventListener('mousemove', handleMove);
        parentDocument.addEventListener('mouseup', handleEnd);

        // Sự kiện chạm
        fab.addEventListener('touchstart', handleStart, { passive: false });
        parentDocument.addEventListener('touchmove', handleMove, { passive: false });
        parentDocument.addEventListener('touchend', handleEnd, { passive: false });
    }

    // ============ Lưu vị trí (persistence) ============
    function savePosition() {
        try {
            const data = {
                top: state.position.top,
                left: state.position.left,
                isExpanded: state.isExpanded
            };
            localStorage.setItem(CONFIG.STORAGE_KEY, JSON.stringify(data));
        } catch (e) {
            console.error('[FloatingMenuManager] Lưu vị trí thất bại:', e);
        }
    }

    function loadPosition() {
        try {
            const saved = localStorage.getItem(CONFIG.STORAGE_KEY);
            if (saved) {
                const data = JSON.parse(saved);
                state.position.top = data.top || 100;
                state.position.left = data.left || 20;
                // Không khôi phục trạng thái mở, luôn bắt đầu từ trạng thái đóng
            }
        } catch (e) {
            console.error('[FloatingMenuManager] Tải vị trí thất bại:', e);
        }
    }

    // ============ Điều chỉnh vị trí vào vùng nhìn thấy ============
    function adjustPositionToViewport() {
        if (!state.elements.main) return;

        const maxLeft = window.parent.innerWidth - CONFIG.MAIN_SIZE;
        const maxTop = window.parent.innerHeight - CONFIG.MAIN_SIZE;

        // Đảm bảo bóng nổi nằm trong vùng nhìn thấy
        let adjusted = false;

        if (state.position.left > maxLeft) {
            state.position.left = Math.max(0, maxLeft);
            adjusted = true;
        }

        if (state.position.top > maxTop) {
            state.position.top = Math.max(0, maxTop);
            adjusted = true;
        }

        if (state.position.left < 0) {
            state.position.left = 0;
            adjusted = true;
        }

        if (state.position.top < 0) {
            state.position.top = 0;
            adjusted = true;
        }

        // Nếu vị trí bị điều chỉnh, cập nhật DOM và lưu lại
        if (adjusted) {
            state.elements.main.style.left = state.position.left + 'px';
            state.elements.main.style.top = state.position.top + 'px';
            updateSubContainerPosition();
            savePosition();
        }
    }

    // ============ Lắng nghe thay đổi kích thước cửa sổ ============
    function bindWindowResize() {
        let resizeTimer = null;
        window.parent.addEventListener('resize', function() {
            // Sử dụng debounce, tránh điều chỉnh liên tục
            if (resizeTimer) clearTimeout(resizeTimer);
            resizeTimer = setTimeout(function() {
                adjustPositionToViewport();
                resizeTimer = null;
            }, 100);
        });
    }

    // ============ API công khai ============
    const FloatingMenuManager = {
        /**
         * Đăng ký nút phụ
         * @param {Object} config - Cấu hình nút
         * @param {string} config.id - ID duy nhất của nút
         * @param {string|HTMLElement} config.icon - Biểu tượng (có thể là emoji, chuỗi SVG hoặc HTML)
         * @param {string} config.label - Nhãn nút (dùng để debug)
         * @param {Function} config.onClick - Hàm callback khi click
         * @param {string} config.color - Màu nền gradient
         * @param {number} config.order - Thứ tự sắp xếp (tùy chọn, mặc định theo thứ tự đăng ký)
         */
        registerButton: function(config) {
            if (!config || !config.id) {
                console.error('[FloatingMenuManager] Đăng ký thất bại: thiếu tham số bắt buộc id');
                return false;
            }

            // Kiểm tra xem đã đăng ký chưa
            const existingIndex = state.buttons.findIndex(btn => btn.id === config.id);
            if (existingIndex !== -1) {
                console.warn('[FloatingMenuManager] Nút đã tồn tại, sẽ cập nhật cấu hình:', config.id);
                state.buttons[existingIndex] = config;
            } else {
                state.buttons.push(config);
            }

            // Sắp xếp theo order
            state.buttons.sort((a, b) => (a.order || 99) - (b.order || 99));

            // Render lại bóng phụ
            if (state.elements.subContainer) {
                renderSubFabs();
            }

            console.log('[FloatingMenuManager] Đăng ký thành công:', config.id);
            return true;
        },

        /**
         * Hủy đăng ký nút
         * @param {string} id - ID nút
         */
        unregisterButton: function(id) {
            const index = state.buttons.findIndex(btn => btn.id === id);
            if (index !== -1) {
                state.buttons.splice(index, 1);
                if (state.elements.subContainer) {
                    renderSubFabs();
                }
                console.log('[FloatingMenuManager] Hủy đăng ký:', id);
                return true;
            }
            return false;
        },

        /**
         * Mở menu
         */
        expand: function() {
            expand();
        },

        /**
         * Đóng menu
         */
        collapse: function() {
            collapse();
        },

        /**
         * Chuyển đổi mở/đóng
         */
        toggle: function() {
            toggle();
        },

        /**
         * Khởi tạo trình quản lý
         */
        init: function() {
            console.log('[FloatingMenuManager] Đang khởi tạo...');

            // Dọn dẹp instance cũ
            this.destroy();

            // Tải vị trí đã lưu
            loadPosition();

            // Chèn style
            injectStyles();

            // Tạo bóng nổi chính
            createMainFab();

            // Tạo container bóng phụ
            createSubContainer();

            // Xử lý hàng đợi chờ đăng ký khi module tải trước FMM
            var pending = window.parent._fmmPendingRegistrations;
            if (pending && pending.length) {
                pending.forEach(function(config) {
                    FloatingMenuManager.registerButton(config);
                });
                window.parent._fmmPendingRegistrations = [];
                console.log('[FloatingMenuManager] Đã xử lý ' + pending.length + ' nút chờ đăng ký');
            }

            // Render bóng phụ đã đăng ký
            renderSubFabs();

            // Điều chỉnh vị trí vào vùng nhìn thấy
            adjustPositionToViewport();

            // Ràng buộc lắng nghe thay đổi kích thước cửa sổ
            bindWindowResize();

            console.log('[FloatingMenuManager] Khởi tạo hoàn tất');
        },

        /**
         * Hủy trình quản lý
         */
        destroy: function() {
            // Xóa phần tử DOM (qua tham chiếu state)
            if (state.elements.main) {
                state.elements.main.remove();
                state.elements.main = null;
            }
            if (state.elements.subContainer) {
                state.elements.subContainer.remove();
                state.elements.subContainer = null;
            }

            // Dọn dẹp phần tử mồ côi thông qua selector (state cũ đã mất khi chạy lại script)
            parentDocument.querySelectorAll('.fmm-main-fab').forEach(function(el) { el.remove(); });
            parentDocument.querySelectorAll('.fmm-sub-container').forEach(function(el) { el.remove(); });

            // Xóa style đã chèn
            const styles = parentDocument.getElementById('floating-menu-manager-styles');
            if (styles) styles.remove();

            // Xóa mảng bóng phụ
            state.elements.subs = [];

            // Xóa nút đã đăng ký
            state.buttons = [];

            // Đặt lại trạng thái
            state.isExpanded = false;
            state.isDragging = false;
            state.hasMoved = false;

            console.log('[FloatingMenuManager] Đã hủy');
        },

        /**
         * Lấy trạng thái hiện tại
         */
        getState: function() {
            return {
                isExpanded: state.isExpanded,
                buttonCount: state.buttons.length,
                position: { ...state.position }
            };
        },

        /**
         * Lấy danh sách nút đã đăng ký
         */
        getButtons: function() {
            return state.buttons.map(btn => ({
                id: btn.id,
                label: btn.label,
                order: btn.order
            }));
        }
    };

    // ============ Xuất ra global ============
    if (typeof window !== 'undefined') {
        window.parent.FloatingMenuManager = FloatingMenuManager;
        console.log('[FloatingMenuManager] Đã tải vào window.parent.FloatingMenuManager');
    }

    // ============ Tự động khởi tạo ============
    if (parentDocument.readyState === 'loading') {
        parentDocument.addEventListener('DOMContentLoaded', function() {
            FloatingMenuManager.init();
        });
    } else {
        FloatingMenuManager.init();
    }

    // ============ Tự động dọn dẹp ============
    $(window).on('pagehide', function() {
        console.log('[FloatingMenuManager] Gỡ cài đặt script, thực hiện dọn dẹp...');
        FloatingMenuManager.destroy();
    });

})();

/**
 * Module chính Điện thoại nhỏ - Phiên bản Script JS Trợ thủ Quán rượu 
 * * Quan trọng: Script trợ thủ chạy trong iframe, phải dùng $ (jQuery) để thao tác DOM trang cha
 */

// ============ Tham số cấu hình ============
const PHONE_CONFIG = {
    id: 'tavern-phone-system',
    phoneWidth: 408,
    phoneHeight: 880,
    frameImage: 'https://cdn.jsdelivr.net/gh/yyk9137/st-phone-ui@main/Asset/phone-frame.png',
    defaultWallpaper: 'https://c4.wallpaperflare.com/wallpaper/297/22/531/anime-scenery-landscape-sky-clouds-wallpaper-preview.jpg',
    storageKey: 'tavernPhoneSettings',
};

// ============ Lấy document của trang cha ============
const parentDocument = window.parent.document;

// ============ Hàm tiện ích ============
function getStorageKey(suffix) {
    let characterName = 'default';
    try {
        if (typeof getCharacterName === 'function') {
            characterName = getCharacterName() || 'default';
        }
    } catch (e) { }
    return PHONE_CONFIG.storageKey + '_' + characterName + (suffix ? '_' + suffix : '');
}

// ============ Quản lý trạng thái toàn cục ============
// Gắn vào cửa sổ cha để các script khác cũng có thể truy cập
window.parent.PhoneSystem = window.parent.PhoneSystem || {
    isOpen: false,
    currentApp: null,
    registeredApps: new Map(),
    appRenderers: {},
    settings: null,
    eventListeners: new Map(),
    iframeWindow: null,

    registerApp: function (appConfig) {
        var id = appConfig.id;
        var name = appConfig.name;
        var icon = appConfig.icon;
        var color = appConfig.color;
        var order = appConfig.order || 99;
        if (!id || !name) {
            console.error('[PhoneSystem] Đăng ký APP thất bại: thiếu tham số bắt buộc');
            return false;
        }
        this.registeredApps.set(id, { id: id, name: name, icon: icon, color: color, order: order });
        console.log('[PhoneSystem] APP đã đăng ký:', name);
        this.emit('app-registered', { id: id, name: name });
        if (this.iframeWindow) {
            this.iframeWindow.postMessage({ type: 'render-apps' }, '*');
        }
        return true;
    },

    registerRenderer: function(appId, rendererFunction) {
        if (!appId || typeof rendererFunction !== 'function') {
            console.error('[PhoneSystem] Đăng ký trình render thất bại: thiếu tham số bắt buộc');
            return false;
        }
        this.appRenderers[appId] = rendererFunction;
        console.log('[PhoneSystem] Trình render đã đăng ký:', appId);
        return true;
    },

    openApp: function (appId) {
        console.log('[PhoneSystem] openApp được gọi, appId:', appId);
        var app = this.registeredApps.get(appId);
        if (!app) {
            console.error('[PhoneSystem] APP không tồn tại:', appId);
            return;
        }
        this.currentApp = appId;
        console.log('[PhoneSystem] Chuẩn bị emit sự kiện app-opened, số lượng listener:', this.eventListeners.get('app-opened')?.length || 0);
        this.emit('app-opened', { id: appId, app: app });
        if (this.iframeWindow) {
            this.iframeWindow.postMessage({ type: 'open-app', appId: appId }, '*');
        }
    },

    goHome: function () {
        this.currentApp = null;
        this.emit('go-home');
        if (this.iframeWindow) {
            this.iframeWindow.postMessage({ type: 'go-home' }, '*');
        }
    },

    getSettings: function () {
        if (!this.settings) this.loadSettings();
        return this.settings;
    },

    loadSettings: function () {
        try {
            var saved = localStorage.getItem(getStorageKey());
            this.settings = saved ? JSON.parse(saved) : this.getDefaultSettings();
        } catch (e) {
            this.settings = this.getDefaultSettings();
        }
        return this.settings;
    },

    saveSettings: function (newSettings) {
        this.settings = Object.assign({}, this.settings, newSettings);
        try {
            localStorage.setItem(getStorageKey(), JSON.stringify(this.settings));
            this.emit('settings-changed', this.settings);
        } catch (e) { }
    },

    getDefaultSettings: function () {
        return {
            wallpaper: PHONE_CONFIG.defaultWallpaper,
            apiConfig: {
                provider: 'openai',
                apiKey: '',
                apiUrl: 'https://api.openai.com/v1/chat/completions',
                model: 'gpt-4o-mini',
                maxTokens: 2048,
                temperature: 0.7,
            },
        };
    },

    on: function (event, callback) {
        console.log('[PhoneSystem] Đăng ký listener sự kiện:', event);
        if (!this.eventListeners.has(event)) {
            this.eventListeners.set(event, []);
        }
        this.eventListeners.get(event).push(callback);
        console.log('[PhoneSystem] Sự kiện', event, 'số lượng listener hiện tại:', this.eventListeners.get(event).length);
    },

    off: function (event, callback) {
        if (!this.eventListeners.has(event)) return;
        var listeners = this.eventListeners.get(event);
        var index = listeners.indexOf(callback);
        if (index > -1) listeners.splice(index, 1);
    },

    emit: function (event, data) {
        if (!this.eventListeners.has(event)) return;
        this.eventListeners.get(event).forEach(function (cb) {
            try { cb(data); } catch (e) { console.error('[PhoneSystem] Lỗi xử lý sự kiện:', e); }
        });
    },

    callExternalAPI: async function (messages, options) {
        options = options || {};
        var settings = this.getSettings();
        var config = settings.apiConfig;

        if (!config.apiKey) {
            throw new Error('Vui lòng cấu hình API Key trong phần cài đặt trước');
        }

        // Đảm bảo định dạng API URL chính xác
        var apiUrl = config.apiUrl || 'https://api.openai.com/v1/chat/completions';
        apiUrl = apiUrl.trim();
        // Xóa dấu gạch chéo ở cuối
        while (apiUrl.endsWith('/')) apiUrl = apiUrl.slice(0, -1);
        // Nếu URL không chứa đường dẫn chat/completions, tự động thêm vào
        if (!apiUrl.includes('/chat/completions')) {
            if (!apiUrl.includes('/v1')) {
                apiUrl += '/v1/chat/completions';
            } else {
                apiUrl += '/chat/completions';
            }
        }

        var requestBody = {
            model: options.model || config.model,
            messages: messages,
            max_tokens: options.maxTokens || config.maxTokens,
            temperature: options.temperature !== undefined ? options.temperature : config.temperature,
            stream: false,
        };

        console.log('[PhoneSystem] Yêu cầu API:', apiUrl);

        var response = await fetch(apiUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': 'Bearer ' + config.apiKey,
            },
            body: JSON.stringify(requestBody),
        });

        // Kiểm tra Content-Type của phản hồi
        var contentType = response.headers.get('content-type') || '';
        if (contentType.includes('text/html')) {
            throw new Error('API trả về HTML thay vì JSON, vui lòng kiểm tra lại cấu hình API URL');
        }

        if (!response.ok) {
            var error = await response.text();
            throw new Error('Yêu cầu API thất bại: ' + response.status + ' - ' + error);
        }

        var data = await response.json();
        return data.choices && data.choices[0] && data.choices[0].message ? data.choices[0].message.content : '';
    },

    getAppsForRender: function () {
        return Array.from(this.registeredApps.values()).sort(function (a, b) { return a.order - b.order; });
    },

    // ============ Hệ thống Tin tức ============
    newsSystem: {
        lastKnownDate: null,
        dateCheckInterval: null,
        currentChatId: null,
        newsData: {
            headlines: [],
            lastUpdate: null,
            isLoading: false
        },

        // Lấy ID cuộc trò chuyện hiện tại
        getChatId: function () {
            try {
                var ctx = window.parent.SillyTavern?.getContext?.();
                if (!ctx) return 'default';
                if (typeof ctx.getCurrentChatId === 'function') {
                    var chatId = ctx.getCurrentChatId();
                    if (chatId) return String(chatId);
                }
                if (ctx.chatId) return String(ctx.chatId);
                if (ctx.characterId !== undefined && ctx.characters && ctx.characters[ctx.characterId]) {
                    var charChat = ctx.characters[ctx.characterId].chat;
                    if (charChat) return String(charChat);
                }
                return 'default';
            } catch (e) { return 'default'; }
        },

        getStorageKey: function (suffix) {
            return 'phone_news_' + this.getChatId() + '_' + suffix;
        },

        extractFromMessageText: function () {
            // Đã vô hiệu hóa chức năng trích xuất dữ liệu Căn hộ/Khách thuê
            return null;
        },

        // Lấy ngày thực tế hiện tại
        getCurrentGameDate: function () {
            let d = new Date();
            return d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');
        },

        getGameState: function () {
            // Đã vô hiệu hóa
            return null;
        },

        // Lấy ngữ cảnh trò chuyện gần đây (3 phản hồi AI + 3 trò chuyện User)
        getRecentChatContext: function () {
            try {
                var ctx = window.parent.SillyTavern?.getContext?.();
                if (!ctx || !ctx.chat || !Array.isArray(ctx.chat)) return '';

                var aiMessages = [];
                var userMessages = [];

                for (var i = ctx.chat.length - 1; i >= 0 && (aiMessages.length < 3 || userMessages.length < 3); i--) {
                    var msg = ctx.chat[i];
                    if (msg && msg.mes) {
                        var text = msg.mes
                            .replace(/<[^>]*>/g, '')
                            .replace(/\{\{[^}]*\}\}/g, '')
                            .replace(/\[\[[^\]]*\]\]/g, '')
                            .trim();
                        if (text) {
                            if (msg.is_user === true && userMessages.length < 3) {
                                userMessages.unshift('Người chơi: ' + text);
                            } else if (msg.is_user !== true && aiMessages.length < 3) {
                                aiMessages.unshift('AI: ' + text);
                            }
                        }
                    }
                }

                return userMessages.concat(aiMessages).join('\n');
            } catch (e) {
                console.error('[Hệ thống Tin tức] Lấy lịch sử trò chuyện thất bại:', e);
                return '';
            }
        },

        saveNewsToVariable: function () {
            var self = this;
            try {
                var newsText = self.newsData.headlines.map(function (news) {
                    return '【' + news.tag + '】' + news.title + ': ' + news.summary;
                }).join('\n');

                var command = '/setvar key=phone_news ' + newsText;
                if (window.parent.executeSlashCommands) {
                    window.parent.executeSlashCommands(command);
                } else if (window.parent.SillyTavern && window.parent.SillyTavern.getContext) {
                    var context = window.parent.SillyTavern.getContext();
                    if (context.executeSlashCommands) {
                        context.executeSlashCommands(command);
                    }
                }

                localStorage.setItem(self.getStorageKey('data'), JSON.stringify({
                    headlines: self.newsData.headlines,
                    lastUpdate: self.newsData.lastUpdate
                }));
            } catch (e) {
                console.error('[Hệ thống Tin tức] Lưu thất bại:', e);
            }
        },

        // Tạo tin tức
        generateNews: async function (isAuto) {
            var self = this;
            if (self.newsData.isLoading) return false;
            self.newsData.isLoading = true;

            try {
                var settings = window.parent.PhoneSystem.getSettings();
                if (!settings.apiConfig || !settings.apiConfig.apiKey) {
                    throw new Error('Vui lòng cấu hình API Key trong cài đặt Điện thoại trước');
                }

                var chatContext = self.getRecentChatContext();

                // Môi trường đã dọn dẹp sạch sẽ
                var contextInfo = 'Đây là bối cảnh hiện tại của người chơi (dựa trên các cuộc trò chuyện gần đây):\n\n' + (chatContext || 'Chưa có sự kiện gì đặc biệt.');

                var systemPrompt = 'Bạn là một biên tập viên tin tức. Dựa trên sự kiện và cuộc trò chuyện gần đây của người chơi, hãy tạo 3-5 tiêu đề tin tức ngắn gọn.\n' +
                    'Tin tức cần thú vị, phản ánh hoặc liên quan một cách ẩn ý đến hoạt động, chủ đề trò chuyện gần đây.\n\n' +
                    'Vui lòng trả về định dạng JSON, với cấu trúc như sau:\n' +
                    '{\n  "headlines": [\n    {"tag": "Chủ đề", "title": "Tiêu đề", "summary": "Tóm tắt ngắn", "source": "Nguồn", "time": "Thời gian"},\n    ...\n  ]\n}';

                var userPrompt = contextInfo + '\n\nVui lòng dựa vào bối cảnh trên để tạo tin tức hôm nay.';

                var result = await window.parent.PhoneSystem.callExternalAPI([
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ]);

                if (result) {
                    var parsed = null;
                    try {
                        parsed = JSON.parse(result);
                    } catch (e) {
                        var jsonMatch = result.match(/\{[\s\S]*\}/);
                        if (jsonMatch) parsed = JSON.parse(jsonMatch[0]);
                    }

                    if (parsed && parsed.headlines) {
                        self.newsData.headlines = parsed.headlines;
                        self.newsData.lastUpdate = new Date();
                        self.saveNewsToVariable();

                        var currentDate = self.getCurrentGameDate();
                        if (currentDate) {
                            localStorage.setItem(self.getStorageKey('last_date'), currentDate);
                        }

                        try {
                            if (window.parent && window.parent.toastr) {
                                window.parent.toastr.info('📰 Tin tức hôm nay đã được cập nhật');
                            }
                        } catch (e) { }

                        window.parent.PhoneSystem.emit('news-updated', self.newsData);
                        return true;
                    }
                }
                throw new Error('Không thể phân tích dữ liệu tin tức');
            } catch (e) {
                console.error('[Hệ thống Tin tức] Lỗi tạo tin tức:', e);
                try {
                    if (!isAuto && window.parent && window.parent.toastr) {
                        window.parent.toastr.error('Lấy tin tức thất bại: ' + e.message);
                    }
                } catch (e2) { }
                return false;
            } finally {
                self.newsData.isLoading = false;
            }
        },

        // Kiểm tra thay đổi ngày
        checkDateAndGenerate: function () {
            var self = this;
            var currentChatId = self.getChatId();
            if (currentChatId !== self.currentChatId) {
                self.loadNewsForCurrentChat();
                return;
            }

            var currentDate = self.getCurrentGameDate();
            if (!currentDate) return;

            var savedDate = localStorage.getItem(self.getStorageKey('last_date'));

            if (self.lastKnownDate === null) {
                self.lastKnownDate = currentDate;
                if (savedDate && savedDate !== currentDate) {
                    self.generateNews(true);
                }
                return;
            } else if (currentDate !== self.lastKnownDate) {
                self.lastKnownDate = currentDate;
                self.generateNews(true);
            }
        },

        loadNewsForCurrentChat: function () {
            var self = this;
            var chatId = self.getChatId();

            self.lastKnownDate = null;
            self.currentChatId = chatId;
            self.newsData.headlines = [];
            self.newsData.lastUpdate = null;

            try {
                var storageKey = self.getStorageKey('data');
                var saved = localStorage.getItem(storageKey);
                if (saved) {
                    var data = JSON.parse(saved);
                    self.newsData.headlines = data.headlines || [];
                    self.newsData.lastUpdate = data.lastUpdate ? new Date(data.lastUpdate) : null;
                }
            } catch (e) {}

            try {
                if (typeof PhoneSystem !== 'undefined' && PhoneSystem.emit) {
                    PhoneSystem.emit('news-updated', self.newsData);
                } else if (window.PhoneSystem && window.PhoneSystem.emit) {
                    window.PhoneSystem.emit('news-updated', self.newsData);
                }
            } catch (e) {}
        },

        start: function () {
            var self = this;
            if (self.dateCheckInterval) return;

            self.loadNewsForCurrentChat();

            setTimeout(function () {
                self.checkDateAndGenerate();
                var eventOn = window.parent.eventOn;
                var checkTimeout = null;

                var debouncedCheck = function () {
                    if (checkTimeout) clearTimeout(checkTimeout);
                    checkTimeout = setTimeout(function () {
                        if (window.parent.requestIdleCallback) {
                            window.parent.requestIdleCallback(function () {
                                self.checkDateAndGenerate();
                            }, { timeout: 2000 });
                        } else {
                            self.checkDateAndGenerate();
                        }
                    }, 1000);
                };

                if (typeof eventOn === 'function') {
                    eventOn('message_received', debouncedCheck);
                    eventOn('message_sent', debouncedCheck);

                    eventOn('chat_id_changed', function (chatFileName) {
                        if (chatFileName) {
                            setTimeout(function () {
                                self.loadNewsForCurrentChat();
                                setTimeout(function () {
                                    self.checkDateAndGenerate();
                                }, 1000);
                            }, 1000);
                        }
                    });

                    eventOn('chatLoaded', function () {
                        setTimeout(function () {
                            self.loadNewsForCurrentChat();
                            self.checkDateAndGenerate();
                        }, 500);
                    });
                }

                self.dateCheckInterval = setInterval(function () {
                    self.checkDateAndGenerate();
                }, 30000);
            }, 3000);
        }
    }
};

if (!window.parent.PhoneSystem.appRenderers) {
    window.parent.PhoneSystem.appRenderers = {};
}
if (typeof window.parent.PhoneSystem.registerRenderer !== 'function') {
    window.parent.PhoneSystem.registerRenderer = function(appId, rendererFunction) {
        if (!appId || typeof rendererFunction !== 'function') return false;
        this.appRenderers[appId] = rendererFunction;
        return true;
    };
}

// ============ Dọn dẹp instance cũ ============
$('#' + PHONE_CONFIG.id + '-fab').remove();
$('#' + PHONE_CONFIG.id + '-overlay').remove();
$('#' + PHONE_CONFIG.id + '-container').remove();
$('#' + PHONE_CONFIG.id + '-styles').remove();

// ============ Phát hiện thiết bị di động ============
function isMobile() {
    return window.parent.innerWidth <= 1024 || /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);
}

// ============ Tính toán tỷ lệ thu phóng thông minh ============
function calculateOptimalScale() {
    var vw = window.parent.innerWidth;
    var vh = window.parent.innerHeight;

    if (isMobile()) {
        var marginW = 40;
        var marginH = 80;
        var availableWidth = vw - marginW;
        var availableHeight = vh - marginH;
        var scaleByWidth = availableWidth / PHONE_CONFIG.phoneWidth;
        var scaleByHeight = availableHeight / PHONE_CONFIG.phoneHeight;
        var optimalScale = Math.min(scaleByWidth, scaleByHeight);
        optimalScale = Math.max(0.6, Math.min(0.85, optimalScale));
        return optimalScale;
    } else {
        return 0.85;
    }
}

// ============ Tạo style ============
var styleId = PHONE_CONFIG.id + '-styles';
var styles = '\
#' + PHONE_CONFIG.id + '-fab {\
    position: fixed;\
    width: 56px;\
    height: 56px;\
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\
    border-radius: 50%;\
    display: flex;\
    align-items: center;\
