        // ============ Lấy bối cảnh truyện từ SillyTavern ============
        function getStoryContext() {
            try {
                var ctx = window.parent.SillyTavern?.getContext?.();
                if (!ctx || !ctx.chat || !Array.isArray(ctx.chat)) return '';

                var recentMessages = ctx.chat.slice(-15);
                var historyText = '';

                for (var i = 0; i < recentMessages.length; i++) {
                    var msg = recentMessages[i];
                    if (msg && msg.mes) {
                        var cleanText = msg.mes
                            .replace(/<[^>]*>/g, '')
                            .replace(/\{\{[^}]*\}\}/g, '')
                            .replace(/\[\[[^\]]*\]\]/g, '')
                            .trim();

                        if (cleanText) {
                            historyText += `${msg.is_user ? 'Người chơi' : 'Nhân vật'}: ${cleanText}\n`;
                        }
                    }
                }
                return historyText;
            } catch (e) {
                console.warn('[APP Tin tức] Lỗi khi lấy lịch sử chat:', e);
                return '';
            }
        }

        // ============ Gọi API tạo tin tức đặc biệt/dị giới ============
        async function fetchSpecialNewsItem() {
            try {
                // Sử dụng API cấu hình trong PhoneSystem
                var settings = window.parent.PhoneSystem.getSettings();
                if (!settings.apiConfig || !settings.apiConfig.apiKey) {
                    return null;
                }

                const chatContext = getStoryContext();
                const systemPrompt = `Bạn là một hệ thống tạo tin tức bí ẩn. Dựa vào bối cảnh câu chuyện dưới đây, hãy tạo 1 mẩu tin tức ngắn kỳ lạ và bí ẩn, có thể là tin đồn nhảm, tin khoa học viễn tưởng hoặc thuyết âm mưu có chút liên quan mờ nhạt đến tình trạng của nhân vật.
Trả về đúng định dạng JSON sau, không có gì thêm:
{"tag":"Tin Lạ","title":"...","summary":"...","source":"...","time":"..."}`;

                const userPrompt = `Bối cảnh gần đây:\n\n${chatContext}\n\nTạo tin tức.`;

                const result = await window.parent.PhoneSystem.callExternalAPI([
                    { role: 'system', content: systemPrompt },
                    { role: 'user', content: userPrompt }
                ]);

                if (result) {
                    const jsonMatch = result.match(/\{[\s\S]*\}/);
                    if (jsonMatch) {
                        const parsed = JSON.parse(jsonMatch[0]);
                        parsed._isOtherWorld = true;
                        return parsed;
                    }
                }
                return null;
            } catch (e) {
                console.warn('[APP Tin tức] Không thể tạo tin đặc biệt:', e);
                return null;
