        async function renderNewsList(iframeDoc) {
            const listEl = iframeDoc.getElementById('news-list');
            const newsData = getNewsData();

            if (newsData.isLoading) {
                listEl.innerHTML = `
                    <div class="news-loading">
                        <div class="news-loading-spinner"></div>
                        <div style="color: #666;">Đang lấy tin tức mới nhất...</div>
                    </div>
                `;
                return;
            }

            if (newsData.headlines.length === 0) {
                listEl.innerHTML = `
                    <div id="news-placeholder" style="text-align:center;padding:80px 20px;color:#999">
                        <div style="font-size:64px;margin-bottom:20px;opacity:0.3">📰</div>
                        <div style="font-size:16px;font-weight:500;margin-bottom:8px">Tạm thời chưa có tin tức</div>
                        <div style="font-size:14px">Nhấp vào góc trên bên phải để làm mới và nhận tin nóng hôm nay</div>
                    </div>
                `;
                return;
            }

            const tagColors = {
                '突发': 'breaking', 'Đột phá': 'breaking',
                '本地': 'local', 'Địa phương': 'local',
                '社会': 'social', 'Xã hội': 'social',
                '经济': 'economy', 'Kinh tế': 'economy',
                '天气': 'weather', 'Thời tiết': 'weather',
                '异界': 'otherworld', 'Tin Lạ': 'otherworld'
            };

            let headlines = [...newsData.headlines];

            // Chèn tin tức đặc biệt nếu trúng tỷ lệ
            if (Math.random() < SPECIAL_NEWS_CHANCE) {
                console.log('[APP Tin tức] Đang tạo tin đặc biệt...');
                const otherWorldItem = await fetchSpecialNewsItem();
                if (otherWorldItem) {
                    const insertAt = Math.floor(Math.random() * (headlines.length - 1)) + 1;
                    headlines.splice(insertAt, 0, otherWorldItem);
                }
            }

            listEl.innerHTML = headlines.map((news, index) => {
                const isOtherWorld = news._isOtherWorld === true;
                const tagKey = news.tag || '';
                const tagClass = tagColors[tagKey] || 'local';
                const cardClass = isOtherWorld ? 'news-card other-world' : 'news-card';
                return `
                <div class="${cardClass}" data-index="${index}">
                    <span class="news-tag ${tagClass}">${tagKey || 'Thông tin'}</span>
                    <div class="news-title">${news.title}</div>
                    <div class="news-summary">${news.summary}</div>
                    <div class="news-meta">
                        <span>${news.source || 'Tin nhanh địa phương'}</span>
                        <span>${news.time || 'Vừa xong'}</span>
                    </div>
                </div>
                `;
            }).join('');
        }

        async function refreshNews(iframeDoc) {
            const newsSystem = window.parent.PhoneSystem?.newsSystem;
            if (!newsSystem) {
                if (window.parent.toastr) window.parent.toastr.error('Hệ thống tin tức chưa được khởi tạo');
                return;
            }

            const refreshBtn = iframeDoc.getElementById('news-refresh-btn');
            if (refreshBtn) {
                refreshBtn.disabled = true;
                refreshBtn.innerHTML = 'Đang tải...';
                refreshBtn.style.opacity = '0.6';
            }

            const listEl = iframeDoc.getElementById('news-list');
            if (listEl) {
                listEl.innerHTML = `
                    <div style="text-align:center;padding:60px 0;color:#888">
                        <div class="news-loading-spinner"></div>
                        <div style="font-size:14px">Đang phân tích bối cảnh để tạo tin tức...</div>
                    </div>
                `;
            }

            console.log('[APP Tin tức] Bắt đầu làm mới tin tức...');

            try {
                // Gọi generateNews từ hệ thống chính (Đã được mod ở phone_main)
                const success = await newsSystem.generateNews(false);
                console.log('[APP Tin tức] Kết quả làm mới:', success);

                if (iframeDoc && iframeDoc.getElementById('news-list')) {
                    await renderNewsList(iframeDoc);
                    updateTimeDisplay(iframeDoc);
                }
            } catch (e) {
                console.error('[APP Tin tức] Làm mới thất bại:', e);
                if (window.parent.toastr) window.parent.toastr.error('Làm mới thất bại: ' + e.message);
