                    for(let i=0; i<15; i++) html += `<div class="p-leaf" style="left:${Math.random() * 120 - 10}%; background:url('${leafSvg}') no-repeat center/contain; animation: leafFall ${Math.random() * 6 + 6}s ease-in-out infinite ${Math.random() * -10}s;"></div>`;
                }
