            '@keyframes snowFall { 0% { transform: translateY(-50px) translateX(0); opacity: 0; } 10% { opacity: 1; } 100% { transform: translateY(850px) translateX(30px) rotate(180deg); opacity: 0; } }' +
            '@keyframes leafFall { 0% { transform: translateY(-50px) translateX(0) rotate(0deg); opacity: 0; } 10% { opacity: 1; } 50% { transform: translateY(400px) translateX(40px) rotate(180deg); } 100% { transform: translateY(850px) translateX(-20px) rotate(360deg); opacity: 0; } }' +
            '@keyframes cloudDrift { 0% { transform: translateX(-350px); } 100% { transform: translateX(500px); } }' +
