            };

            // --- TRẠNG THÁI ĐANG TẢI ---
            if (ws.isLoading) {
                var emptyBg = getStaticBackground('sunny', 'day');
                container.innerHTML = '<div style="width:100%; height:100%; background:' + emptyBg + '; transition: background 1.5s ease;">'
