                    + '<div style="font-size:18px;font-weight:600;margin-bottom:12px; ' + textShadow + '">Đang phân tích bối cảnh...</div>'
                    + '<div style="font-size:14px;opacity:0.9; ' + textShadow + '">AI đang đọc dữ liệu chat để tạo thời tiết.</div>'
