            sunEvents.forEach(function(ev) {
                var evHr = parseInt(ev.time.split(':')[0]) + (ev.time.split(':')[1] === '30' ? 0.5 : (ev.time.split(':')[1] === '45' ? 0.75 : 0));
                var evAbs = evHr + (ev.isNextDay ? 24 : 0);
