        // ============ Biến Trạng_thái ============
        let mapInstance = null;
        let currentMarker = null;
        let selectedLocation = null;
        let selectedCompanions = []; // Đổi thành mảng để hỗ trợ chọn nhiều người

        // ============ Tạo HTML APP ============
        function generateAppHTML() {
