    // ==================== Đánh chặn bảng điều khiển ====================
    let currentIframeDoc = null;
    let originalConsole = {};

    function setupConsoleInterceptor() {
        const targetWindow = window.parent;

        // Lưu các phương thức gốc
        originalConsole = {
            log: targetWindow.console.log.bind(targetWindow.console),
            warn: targetWindow.console.warn.bind(targetWindow.console),
            error: targetWindow.console.error.bind(targetWindow.console),
            info: targetWindow.console.info.bind(targetWindow.console)
        };

        // Đánh chặn phương thức console
        ['log', 'warn', 'error', 'info'].forEach(type => {
            targetWindow.console[type] = function (...args) {
                // Gọi phương thức gốc
                originalConsole[type](...args);

                // Ghi vào DebugData
                addLog(type, args);
            };
        });

        console.log('[Trình gỡ lỗi] Đã khởi động đánh chặn bảng điều khiển');
    }

    function addLog(type, args) {
        const message = args.map(arg => {
            if (typeof arg === 'object') {
                try {
                    return JSON.stringify(arg, null, 2);
                } catch (e) {
                    return String(arg);
                }
            }
            return String(arg);
        }).join(' ');

        DebugData.consoleLogs.push({
            type,
            message,
            time: new Date().toLocaleTimeString('zh-CN', { hour12: false })
        });

        // Giới hạn số lượng
        if (DebugData.consoleLogs.length > DebugData.maxLogs) {
            DebugData.consoleLogs.shift();
        }

        // Nếu hiện tại đang ở dạng xem bảng điều khiển, tự động làm mới
        updateLogCount();

        // Làm mới theo Thời_gian thực (nếu mở)
        if (currentIframeDoc && currentIframeDoc.querySelector('.debug-tab.active[data-tab="console"]')) {
            requestAnimationFrame(() => renderConsoleLogs('all', true)); // Chỉ nối thêm hoặc làm mới đơn giản
        }
    }

    // ==================== Đánh chặn API ====================
    function setupAPIInterceptor() {
        const PhoneSystem = window.parent.PhoneSystem;
        if (!PhoneSystem) {
            setTimeout(setupAPIInterceptor, 500);
            return;
        }

        // Lưu phương thức gốc
        const originalCallAPI = PhoneSystem.callExternalAPI.bind(PhoneSystem);

        // Đánh chặn lệnh gọi API
        PhoneSystem.callExternalAPI = async function (messages, options) {
            const startTime = Date.now();
            const apiRecord = {
                id: Date.now(),
                time: new Date().toLocaleTimeString('zh-CN', { hour12: false }),
                model: options?.model || PhoneSystem.getSettings()?.apiConfig?.model || 'unknown',
                messages: messages,
                options: options,
                response: null,
                error: null,
                duration: 0
            };

            try {
                const result = await originalCallAPI(messages, options);
                apiRecord.response = result;
                apiRecord.duration = Date.now() - startTime;
                return result;
            } catch (e) {
                apiRecord.error = e.message;
                apiRecord.duration = Date.now() - startTime;
                throw e;
            } finally {
                DebugData.apiCalls.unshift(apiRecord);
                if (DebugData.apiCalls.length > DebugData.maxApiCalls) {
                    DebugData.apiCalls.pop();
                }
                updateApiCount();
                // Làm mới theo Thời_gian thực
                if (currentIframeDoc && currentIframeDoc.querySelector('.debug-tab.active[data-tab="api"]')) {
                    renderApiCalls();
                }
            }
        };

        // Đồng thời đánh chặn lệnh gọi API của ChatCore (nếu tồn tại)
        if (window.parent.ChatCore) {
            const originalChatCoreAPI = window.parent.ChatCore.callAPI.bind(window.parent.ChatCore);
            window.parent.ChatCore.callAPI = async function (prompt) {
                const startTime = Date.now();
                const apiRecord = {
                    id: Date.now(),
                    time: new Date().toLocaleTimeString('zh-CN', { hour12: false }),
                    model: this.getAPIConfig()?.model || 'unknown',
                    messages: [{ role: 'user', content: prompt }],
                    options: { source: 'ChatCore' },
                    response: null,
                    error: null,
                    duration: 0
                };

                try {
                    const result = await originalChatCoreAPI(prompt);
                    apiRecord.response = result;
                    apiRecord.duration = Date.now() - startTime;
                    return result;
                } catch (e) {
                    apiRecord.error = e.message;
                    apiRecord.duration = Date.now() - startTime;
                    throw e;
                } finally {
                    DebugData.apiCalls.unshift(apiRecord);
                    if (DebugData.apiCalls.length > DebugData.maxApiCalls) {
                        DebugData.apiCalls.pop();
                    }
                    updateApiCount();
                }
            };
        }

        console.log('[Trình gỡ lỗi] Đã khởi động đánh chặn API');
    }

    // ==================== Cập nhật UI ====================
    function updateLogCount() {
        if (!currentIframeDoc) return;
        const badge = currentIframeDoc.getElementById('console-badge');
        if (badge) {
            const errorCount = DebugData.consoleLogs.filter(l => l.type === 'error').length;
            badge.textContent = errorCount > 0 ? errorCount : '';
            badge.style.display = errorCount > 0 ? 'inline-block' : 'none';
        }
    }

    function updateApiCount() {
        if (!currentIframeDoc) return;
        const badge = currentIframeDoc.getElementById('api-badge');
        if (badge) {
            badge.textContent = DebugData.apiCalls.length;
            badge.style.display = DebugData.apiCalls.length > 0 ? 'inline-block' : 'none';
        }
    }

    // ==================== Tạo HTML ====================
    function generateAppHTML() {
        const errorCount = DebugData.consoleLogs.filter(l => l.type === 'error').length;

        return `
            <div class="debug-app">
                <div class="debug-header">
                    <button class="debug-back-btn" id="btn-debug-home">‹</button>
                    <span class="debug-title">DEBUGGER TERMINAL</span>
                    <button class="debug-clear-btn" id="btn-clear-logs">CLEAR</button>
                </div>
                <div class="debug-tabs">
                    <button class="debug-tab active" data-tab="console">
                        CONSOLE
                        <span class="debug-tab-badge" id="console-badge" style="display:${errorCount > 0 ? 'inline-block' : 'none'}">${errorCount || ''}</span>
                    </button>
                    <button class="debug-tab" data-tab="api">
                        API TRACE
                        <span class="debug-tab-badge" id="api-badge" style="display:${DebugData.apiCalls.length > 0 ? 'inline-block' : 'none'}">${DebugData.apiCalls.length || ''}</span>
                    </button>
                </div>
                <div class="debug-filter" id="debug-filter">
                    <button class="filter-btn active" data-filter="all">ALL</button>
                    <button class="filter-btn" data-filter="log">LOG</button>
                    <button class="filter-btn" data-filter="info">INFO</button>
                    <button class="filter-btn" data-filter="warn">WARN</button>
                    <button class="filter-btn" data-filter="error">ERR</button>
                </div>
                <div class="debug-content" id="debug-content">
                    </div>
            </div>
        `;
    }

    function renderConsoleLogs(filter = 'all', append = false) {
        const doc = currentIframeDoc || document;
        const container = doc.getElementById('debug-content');
        if (!container) return;

        // Lấy Trạng_thái bộ lọc hiện tại (nếu không được chỉ định bắt buộc)
        if (filter === 'all') {
            const activeBtn = doc.querySelector('.filter-btn.active');
            if (activeBtn) filter = activeBtn.dataset.filter;
        }

        const logs = filter === 'all'
            ? DebugData.consoleLogs
            : DebugData.consoleLogs.filter(l => l.type === filter);

        if (logs.length === 0) {
            container.innerHTML = `
                <div class="debug-empty">
                    <div class="debug-empty-icon">_</div>
                    <div class="debug-empty-text">NO LOGS AVAILABLE</div>
                    <div style="font-size:10px;color:#333;margin-top:10px">SYSTEM READY</div>
                </div>
            `;
            return;
        }

        // Hiển thị theo thứ tự đảo ngược (mới nhất ở trên)
        const reversedLogs = [...logs].reverse();

        container.innerHTML = reversedLogs.map(log => `
            <div class="log-item ${log.type}">
                <div class="log-time">[${log.time}]</div>
                <div style="display:flex;align-items:center;margin-bottom:2px;">
                     <span class="log-type ${log.type}">${log.type}</span>
                </div>
                <div class="log-message">${escapeHtml(log.message)}</div>
            </div>
        `).join('');
    }

    function renderApiCalls() {
        const doc = currentIframeDoc || document;
        const container = doc.getElementById('debug-content');
        const filterDiv = doc.getElementById('debug-filter');

        if (!container) return;

        // Ẩn bộ lọc (Trang API không cần)
        if (filterDiv) filterDiv.style.display = 'none';

        if (DebugData.apiCalls.length === 0) {
            container.innerHTML = `
                <div class="debug-empty">
                    <div class="debug-empty-icon">⚡</div>
                    <div class="debug-empty-text">NO API REQUESTS</div>
                </div>
            `;
            return;
        }

        container.innerHTML = DebugData.apiCalls.map((api, index) => `
            <div class="api-item ${index === 0 ? 'latest' : ''}" data-id="${api.id}">
                <div class="api-header">
                    <div style="display:flex;align-items:center">
                        <span class="api-method">POST</span>
                        <span class="api-model">${api.model}</span>
                    </div>
                    <div style="display:flex;align-items:center">
                        <span class="api-time">${api.time} • ${api.duration}ms</span>
                        <span class="api-toggle">▼</span>
                    </div>
                </div>
                <div class="api-body">
                    <div class="api-section">
                        <div class="api-section-title">📤 MESSAGES (${api.messages?.length || 0})</div>
                        <div class="api-section-content">${formatMessages(api.messages)}</div>
                    </div>
                    ${api.response ? `
                    <div class="api-section">
                        <div class="api-section-title">📥 RESPONSE</div>
                        <div class="api-section-content" style="color:#a8e6cf">${escapeHtml(api.response)}</div>
                    </div>
                    ` : ''}
                    ${api.error ? `
                    <div class="api-section">
                        <div class="api-section-title">❌ ERROR</div>
                        <div class="api-section-content" style="color:#ff4757;border-color:#ff4757">${escapeHtml(api.error)}</div>
                    </div>
                    ` : ''}
                </div>
            </div>
        `).join('');

        // Liên kết sự kiện mở rộng/thu gọn
        container.querySelectorAll('.api-header').forEach(header => {
            header.addEventListener('click', (e) => {
                const item = header.closest('.api-item');
                const body = item.querySelector('.api-body');
                body.classList.toggle('expanded');
                item.classList.toggle('expanded');
            });
        });
    }

    function formatMessages(messages) {
        if (!messages || messages.length === 0) return '(EMPTY)';

        return messages.map((msg, i) => {
            const role = msg.role || 'unknown';
            const content = msg.content || '';
            const roleClass = `role-${role}`;
            return `<span class="role-badge ${roleClass}">${role.toUpperCase()}</span>\n${escapeHtml(content)}`;
        }).join('\n\n');
    }

    function escapeHtml(text) {
        if (!text) return '';
        const div = document.createElement('div');
        div.textContent = text;
        return div.innerHTML;
    }

    // ==================== Liên kết sự kiện ====================
    function bindEvents() {
        const doc = currentIframeDoc || document;

        // Quay lại màn hình chính
        doc.getElementById('btn-debug-home')?.addEventListener('click', () => {
            const PhoneSystem = window.parent.PhoneSystem;
            if (PhoneSystem) PhoneSystem.goHome();
        });

        // Nút xóa sạch
        doc.getElementById('btn-clear-logs')?.addEventListener('click', () => {
            const activeTab = doc.querySelector('.debug-tab.active')?.dataset.tab;
            if (activeTab === 'console') {
                DebugData.consoleLogs = [];
                renderConsoleLogs();
            } else {
                DebugData.apiCalls = [];
                renderApiCalls();
            }
            updateLogCount();
            updateApiCount();
        });

        // Chuyển đổi thẻ
        doc.querySelectorAll('.debug-tab').forEach(tab => {
            tab.addEventListener('click', () => {
                doc.querySelectorAll('.debug-tab').forEach(t => t.classList.remove('active'));
                tab.classList.add('active');

                const filterDiv = doc.getElementById('debug-filter');

                if (tab.dataset.tab === 'console') {
                    if (filterDiv) filterDiv.style.display = 'flex';
                    renderConsoleLogs();
                } else {
                    renderApiCalls();
                }
            });
        });

        // Nút lọc
        doc.querySelectorAll('.filter-btn').forEach(btn => {
            btn.addEventListener('click', () => {
                doc.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                renderConsoleLogs(btn.dataset.filter);
            });
        });
    }

    // ==================== Tích hợp PhoneSystem ====================
    function waitForPhoneSystem(callback) {
        if (window.parent.PhoneSystem) {
            callback();
        } else {
            setTimeout(() => waitForPhoneSystem(callback), 100);
        }
    }

    function openApp() {
        const phoneSystem = window.parent.PhoneSystem;
        if (!phoneSystem || !phoneSystem.iframeWindow) {
            setTimeout(openApp, 200);
            return;
        }

        const iframeDoc = phoneSystem.iframeWindow.document;
        currentIframeDoc = iframeDoc;

        const appContainer = iframeDoc.getElementById('app-container');
        const homeScreen = iframeDoc.getElementById('home-screen');
        const statusBar = iframeDoc.getElementById('status-bar');

        if (!appContainer) {
            console.error('[Trình gỡ lỗi] Không tìm thấy app-container');
            return;
        }

        if (homeScreen) homeScreen.style.display = 'none';
        appContainer.innerHTML = '';
        appContainer.style.display = 'block';
        appContainer.style.pointerEvents = 'auto';

        if (statusBar) {
            statusBar.classList.remove('light');
            statusBar.classList.add('dark');
        }

        // Tiêm kiểu dáng (Style)
        if (!iframeDoc.getElementById('debug-app-styles')) {
            const style = iframeDoc.createElement('style');
            style.id = 'debug-app-styles';
            style.textContent = APP_STYLES;
            iframeDoc.head.appendChild(style);
        } else {
            iframeDoc.getElementById('debug-app-styles').textContent = APP_STYLES;
        }

        // Tạo nội dung APP
        const appDiv = iframeDoc.createElement('div');
        appDiv.id = 'debug-app-wrapper';
        appDiv.style.cssText = 'width:100%;height:100%;';
        appDiv.innerHTML = generateAppHTML();
        appContainer.appendChild(appDiv);

        // Liên kết sự kiện và kết xuất
        setTimeout(() => {
            bindEvents();
            renderConsoleLogs();
        }, 50);

        console.log('[Trình gỡ lỗi] APP đã mở');
    }

    function closeApp() {
        if (!window.parent) return;
        const phoneSystem = window.parent.PhoneSystem;
        if (!phoneSystem || !phoneSystem.iframeWindow) return;

        try {
            const iframeDoc = phoneSystem.iframeWindow.document;

            const appContainer = iframeDoc.getElementById('app-container');
            if (appContainer) {
                appContainer.innerHTML = '';
                appContainer.style.pointerEvents = 'none';
            }

            const homeScreen = iframeDoc.getElementById('home-screen');
            if (homeScreen) homeScreen.style.display = 'block';

            const statusBar = iframeDoc.getElementById('status-bar');
            if (statusBar) {
                statusBar.classList.remove('dark');
                statusBar.classList.add('light');
            }

            currentIframeDoc = null;
        } catch (e) {
            console.error('[Trình gỡ lỗi] closeApp thất bại:', e);
        }
    }

    // Đăng ký APP
    waitForPhoneSystem(() => {
        console.log('[Trình gỡ lỗi] PhoneSystem đã sẵn sàng, bắt đầu đăng ký');

        window.parent.PhoneSystem.registerApp({
            id: APP_ID,
            name: APP_NAME,
            icon: APP_ICON,
            color: APP_COLOR,
            order: 10
        });

        window.parent.PhoneSystem.on('app-opened', (data) => {
            if (data.id === APP_ID) openApp();
        });

        window.parent.PhoneSystem.on('go-home', closeApp);

        // Khởi động trình đánh chặn
        setupConsoleInterceptor();
        setupAPIInterceptor();

        console.log('[Trình gỡ lỗi] APP đã đăng ký:', APP_NAME);
    });

    // Xuất ra toàn cục
    window.parent.DebugApp = {
        getData: () => DebugData,
        clearLogs: () => { DebugData.consoleLogs = []; },
        clearApiCalls: () => { DebugData.apiCalls = []; }
    };

    console.log('✅ DebugApp Module trình gỡ lỗi đã được tải');

})();

/**
 * Điện thoại nhỏ - Music APP v4.2
 * * Tính năng mới:
 * - Kéo thả sắp xếp danh sách dọc mượt mà (Có vạch chỉ thị vị trí thả)
 * - Đổi icon kéo thả thành 3 dấu gạch ngang (Hamburger icon)
 * - Hỗ trợ Theme Sáng/Tối (Lưu trữ cục bộ)
 * - Quản lý Playlist (Tạo mới, thêm/xóa bài hát, xóa playlist)
 */

(function () {
    'use strict';

    function waitForPhoneSystem(cb) {
        if (window.parent.PhoneSystem) {
            cb();
        } else {
            setTimeout(function () { waitForPhoneSystem(cb); }, 100);
        }
    }

    waitForPhoneSystem(function () {
        console.log('[Music APP] Khởi tạo v4.2');

        // ============ Cấu hình ============
        var APP_ID = 'music';
        var STORAGE_KEY = 'phone_music_v4'; // Vẫn dùng key v4 để bảo toàn dữ liệu cũ
        var AUDIO_ID = 'phone-music-audio';

        // ============ Chủ đề (CSS Variables) ============
        var THEME_VARS = {
            light: '--primary: #ff7e5f; --gradient: linear-gradient(135deg, #ff7e5f 0%, #feb47b 100%); --bg: #f8f9fa; --card: #ffffff; --text: #333333; --textLight: #999999; --heart: #ff4757; --tabBg: rgba(255,255,255,0.95); --border: rgba(0,0,0,0.05); --modalBg: rgba(0,0,0,0.5);',
            dark: '--primary: #ff9a85; --gradient: linear-gradient(135deg, #ff7e5f 0%, #feb47b 100%); --bg: #121212; --card: #1e1e1e; --text: #ffffff; --textLight: #aaaaaa; --heart: #ff4757; --tabBg: rgba(30,30,30,0.95); --border: rgba(255,255,255,0.05); --modalBg: rgba(0,0,0,0.7);'
        };

        // ============ Biểu tượng (Remix Icon) ============
        var I = {
            back: '<i class="ri-arrow-left-line" style="font-size:24px"></i>',
            search: '<i class="ri-search-line" style="font-size:20px"></i>',
            play: '<i class="ri-play-fill" style="font-size:32px"></i>',
            pause: '<i class="ri-pause-fill" style="font-size:32px"></i>',
            prev: '<i class="ri-skip-back-fill" style="font-size:24px"></i>',
            next: '<i class="ri-skip-forward-fill" style="font-size:24px"></i>',
            heart: '<i class="ri-heart-line" style="font-size:24px"></i>',
            heartFill: '<i class="ri-heart-fill" style="font-size:24px;color:var(--heart)"></i>',
            list: '<i class="ri-play-list-line" style="font-size:24px"></i>',
            down: '<i class="ri-arrow-down-s-line" style="font-size:32px"></i>',
            music: '<img src="https://api.iconify.design/ri:netease-cloud-music-fill.svg?color=white" style="width:100%;height:100%">',
            x: '<i class="ri-close-line" style="font-size:24px"></i>',
            stop: '<i class="ri-stop-circle-line" style="font-size:24px"></i>',
            home: '<i class="ri-compass-3-line" style="font-size:24px"></i>',
            library: '<i class="ri-folder-music-line" style="font-size:24px"></i>',
            modeLoop: '<i class="ri-repeat-line" style="font-size:20px"></i>',
            modeOne: '<i class="ri-repeat-one-line" style="font-size:20px"></i>',
            modeShuffle: '<i class="ri-shuffle-line" style="font-size:20px"></i>',
            backToDesk: '<i class="ri-home-fill" style="font-size:22px"></i>',
            moon: '<i class="ri-moon-fill" style="font-size:22px"></i>',
            sun: '<i class="ri-sun-fill" style="font-size:22px"></i>',
            addList: '<i class="ri-add-line" style="font-size:22px"></i>',
            delete: '<i class="ri-delete-bin-line" style="font-size:18px"></i>',
            drag: '<i class="ri-menu-line" style="font-size:20px"></i>' // Đã đổi thành icon 3 gạch
        };

        // ============ Âm thanh toàn cục ============
        var audio = window.parent.document.getElementById(AUDIO_ID);
        if (!audio) {
            audio = window.parent.document.createElement('audio');
            audio.id = AUDIO_ID;
            audio.style.display = 'none';
            window.parent.document.body.appendChild(audio);
        }

        // ============ Trạng_thái ============
        var state = {
            currentSong: null,
            isPlaying: false,
            queue: [],
            queueIndex: -1,
            queueName: '',
            favorites: [],
            playlists: [], 
            history: [],
            playMode: 0, 
            theme: 'light' 
        };

        var doc = null;
        var searchCache = [];
        var lyrics = [];
        var currentTab = 'home';
        var pendingSongToAdd = null; 

        // ============ Lưu trữ cố định ============
        function load() {
            try {
                var s = localStorage.getItem(STORAGE_KEY);
                if (s) {
                    var d = JSON.parse(s);
                    state.favorites = d.favorites || [];
                    state.playlists = d.playlists || [];
                    state.history = d.history || [];
                    state.currentSong = d.currentSong || null;
                    state.queue = d.queue || [];
                    state.queueIndex = typeof d.queueIndex === 'number' ? d.queueIndex : -1;
                    state.queueName = d.queueName || '';
                    state.theme = d.theme || 'light';
                }
            } catch (e) {
                console.error('Tải Trạng_thái thất bại', e);
            }
        }

        function save() {
            try {
                localStorage.setItem(STORAGE_KEY, JSON.stringify({
                    favorites: state.favorites,
                    playlists: state.playlists,
                    history: state.history.slice(0, 50),
                    currentSong: state.currentSong,
                    queue: state.queue,
                    queueIndex: state.queueIndex,
                    queueName: state.queueName,
                    theme: state.theme
                }));
            } catch (e) {
                console.error('Lưu Trạng_thái thất bại', e);
            }
        }

        load();

        if (audio.src && !audio.paused) {
            state.isPlaying = true;
        }

        function getThemeCSS() {
            return ':root, #music-app { ' + THEME_VARS[state.theme] + ' }';
        }

        // ============ HTTP ============
        function httpGet(url) {
            return new Promise(function (resolve) {
                var xhr = new XMLHttpRequest();
                xhr.open('GET', url, true);
                xhr.timeout = 10000;
                xhr.onload = function () {
                    try { resolve(JSON.parse(xhr.responseText)); }
                    catch (e) { resolve(null); }
                };
                xhr.onerror = function () { resolve(null); };
                xhr.ontimeout = function () { resolve(null); };
                xhr.send();
            });
        }

        // ============ Hàm công cụ ============
        function isFav(id) {
            return state.favorites.some(function (s) { return s.id === id; });
        }

        function toggleFav(song) {
            var i = state.favorites.findIndex(function (s) { return s.id === song.id; });
            if (i >= 0) {
                state.favorites.splice(i, 1);
            } else {
                state.favorites.unshift(song);
            }
            save();
            refreshFavBtns();
        }

        function addToHistory(song) {
            state.history = state.history.filter(function (s) { return s.id !== song.id; });
            state.history.unshift(song);
            if (state.history.length > 50) {
                state.history = state.history.slice(0, 50);
            }
            save();
        }

        function refreshFavBtns() {
            if (!doc) return;
            var btns = doc.querySelectorAll('[data-fav]');
            btns.forEach(function (b) {
                var id = parseInt(b.dataset.fav);
                b.innerHTML = isFav(id) ? I.heartFill : I.heart;
            });
        }

        function formatTime(s) {
            if (!s || isNaN(s)) return '0:00';
            var m = Math.floor(s / 60);
            var sec = Math.floor(s % 60);
            return m + ':' + (sec < 10 ? '0' : '') + sec;
        }

        function toggleTheme() {
            state.theme = state.theme === 'light' ? 'dark' : 'light';
            save();
            var styleEl = doc.getElementById('theme-style');
            if (styleEl) styleEl.textContent = getThemeCSS();
            var btn = doc.getElementById('theme-btn');
            if (btn) btn.innerHTML = state.theme === 'dark' ? I.sun : I.moon;
        }

        // ============ Điều khiển phát ============
        function playSong(song, context, contextName, indexInContext) {
            state.currentSong = song;
            state.isPlaying = true;

            if (context && context.length > 0) {
                state.queue = context.slice();
                state.queueIndex = indexInContext || 0;
                state.queueName = contextName || '';
            }

            addToHistory(song);
            save();
            updateUI();

            var idParam = song.mid ? 'mid=' + song.mid : 'id=' + song.id;
            httpGet('https://api.vkeys.cn/v2/music/tencent?' + idParam).then(function (res) {
                if (res && res.data && res.data.url) {
                    audio.src = res.data.url;
                    audio.play().catch(function (e) { console.log('Phát thất bại:', e); });
                    fetchLyrics(song.mid || song.id);
                } else {
                    if (window.parent.toastr) {
                        window.parent.toastr.warning('Bài hát VIP, bỏ qua');
                    }
                    playNext();
                }
            });
        }

        function togglePlay() {
            if (!state.currentSong) return;
            if (state.isPlaying) {
                audio.pause();
            } else {
                audio.play();
            }
        }

        function toggleMode() {
            state.playMode = (state.playMode + 1) % 3;
            var modeName = ['Lặp danh sách', 'Lặp một bài', 'Phát ngẫu nhiên'][state.playMode];
            if (window.parent.toastr) window.parent.toastr.info('Chế độ phát: ' + modeName);
            updateUI();
        }

        function playNext(auto) {
            if (state.queue.length === 0) return;

            if (auto && state.playMode === 1) {
                audio.currentTime = 0;
                audio.play();
                return;
            }

            if (state.playMode === 2) {
                var nextIndex = Math.floor(Math.random() * state.queue.length);
                if (state.queue.length > 1 && nextIndex === state.queueIndex) {
                    nextIndex = (nextIndex + 1) % state.queue.length;
                }
                state.queueIndex = nextIndex;
            } else {
                state.queueIndex = (state.queueIndex + 1) % state.queue.length;
            }

            var song = state.queue[state.queueIndex];
            playSong(song, state.queue, state.queueName, state.queueIndex);
        }

        function playPrev() {
            if (state.queue.length === 0) return;

            if (state.playMode === 2) {
                var nextIndex = Math.floor(Math.random() * state.queue.length);
                state.queueIndex = nextIndex;
            } else {
                state.queueIndex = (state.queueIndex - 1 + state.queue.length) % state.queue.length;
            }

            var song = state.queue[state.queueIndex];
            playSong(song, state.queue, state.queueName, state.queueIndex);
        }

        function playFromQueue(index) {
            if (index < 0 || index >= state.queue.length) return;
            state.queueIndex = index;
            var song = state.queue[index];
            playSong(song, state.queue, state.queueName, index);
        }

        function stopMusic() {
            audio.pause();
            audio.src = '';
            state.currentSong = null;
            state.isPlaying = false;
            state.queue = [];
            state.queueIndex = -1;
            save();
            updateUI();
        }

        function seekTo(pct) {
            if (!audio.duration) return;
            audio.currentTime = (pct / 100) * audio.duration;
        }

        // ============ Lời bài hát ============
        function fetchLyrics(id) {
            lyrics = [];
            if (!doc) return;
            var el = doc.getElementById('lyric');
            if (el) el.textContent = '♪ Đang tải lời bài hát...';

            httpGet('https://api.vkeys.cn/v2/music/tencent/lyric?mid=' + id).then(function (res) {
                if (res && res.data && res.data.lyric) {
                    var lines = res.data.lyric.split('\n');
                    var re = /\[(\d{2}):(\d{2})\.(\d{2,3})\]/g;
                    lines.forEach(function (line) {
                        var matches = [];
                        var match;
                        while ((match = re.exec(line)) !== null) {
                            matches.push(match);
                        }
                        re.lastIndex = 0;
                        var text = line.replace(re, '').trim();
                        if (matches.length && text) {
                            matches.forEach(function (m) {
                                lyrics.push({
                                    time: parseInt(m[1]) * 60 + parseInt(m[2]) + parseInt(m[3]) / 1000,
                                    text: text
                                });
                            });
                        }
                    });
                    lyrics.sort(function (a, b) { return a.time - b.time; });
                    if (el && lyrics.length) el.textContent = lyrics[0].text;
                    else if (el) el.textContent = '♪ Tạm thời chưa có lời bài hát';
                } else if (el) {
                    el.textContent = '♪ Tạm thời chưa có lời bài hát';
                }
            }).catch(function () {
                if (el) el.textContent = '♪ Tạm thời chưa có lời bài hát';
            });
        }

        function updateLyric(time) {
            if (!lyrics.length || !doc) return;
            var el = doc.getElementById('lyric');
            if (!el) return;
            var cur = lyrics[0];
            for (var i = lyrics.length - 1; i >= 0; i--) {
                if (time >= lyrics[i].time) {
                    cur = lyrics[i];
                    break;
                }
            }
            if (cur && el.textContent !== cur.text) {
                el.textContent = cur.text;
            }
        }

        // ============ Cập nhật UI ============
        function updateUI() {
            if (!doc) return;

            var song = state.currentSong;
            var hasSong = !!song;

            var mini = doc.getElementById('mini');
            var content = doc.getElementById('content');
            if (mini) mini.style.display = hasSong ? 'flex' : 'none';
            if (content) content.style.paddingBottom = hasSong ? '114px' : '50px';

            if (hasSong) {
                setById('mini-title', song.name);
                setImgById('mini-cover', song.cover);
                setHtmlById('mini-play', state.isPlaying ? I.pause : I.play);

                setById('full-title', song.name);
                setById('full-artist', song.singer);
                setImgById('full-cover', song.cover);
                setBgById('full-bg', song.cover);
                setHtmlById('full-play', state.isPlaying ? I.pause : I.play);

                var modeIcon = state.playMode === 1 ? I.modeOne : (state.playMode === 2 ? I.modeShuffle : I.modeLoop);
                var modeColor = state.playMode === 0 ? 'var(--textLight)' : 'var(--primary)';
                var modeBtn = doc.getElementById('mode-btn');
                if (modeBtn) {
                    modeBtn.innerHTML = modeIcon;
                    modeBtn.style.color = modeColor;
                }

                var favBtn = doc.getElementById('full-fav');
                if (favBtn) {
                    favBtn.dataset.fav = song.id;
                    favBtn.innerHTML = isFav(song.id) ? I.heartFill : I.heart;
                }

                setById('queue-info', state.queueName ? state.queueName.toUpperCase() : 'PLAYING FROM LIBRARY');
            }
        }

        function setById(id, val) {
            var e = doc.getElementById(id);
            if (e) e.textContent = val;
        }

        function setHtmlById(id, val) {
            var e = doc.getElementById(id);
            if (e) e.innerHTML = val;
        }

        function setImgById(id, val) {
            var e = doc.getElementById(id);
            if (e) e.src = val;
        }

        function setBgById(id, val) {
            var e = doc.getElementById(id);
            if (e) e.style.backgroundImage = "url('" + val + "')";
        }

        function updateProgress() {
            if (!audio.duration || !doc) return;
            var pct = (audio.currentTime / audio.duration) * 100;

            var miniProg = doc.getElementById('mini-prog');
            var fill = doc.getElementById('prog-fill');
            var thumb = doc.getElementById('prog-thumb');
            var cur = doc.getElementById('time-cur');
            var total = doc.getElementById('time-total');

            if (miniProg) miniProg.style.width = pct + '%';
            if (fill) fill.style.width = pct + '%';
            if (thumb) thumb.style.left = pct + '%';
            if (cur) cur.textContent = formatTime(audio.currentTime);
            if (total) total.textContent = formatTime(audio.duration);

            updateLyric(audio.currentTime);
        }

        // ============ Tìm kiếm ============
        var searchKeyword = '';
        var searchPage = 1;
        var hasMoreResults = false;

        function search(kw, page) {
            if (!kw || !doc) return;
            var content = doc.getElementById('content');
            if (!content) return;

            searchKeyword = kw;
            searchPage = page || 1;

            if (searchPage === 1) {
                content.innerHTML = '<div style="padding:40px 20px;text-align:center"><div style="font-size:32px;animation:spin 1s linear infinite;opacity:0.5">⏳</div></div>';
                searchCache = [];
            }

            httpGet('https://api.vkeys.cn/v2/music/tencent/search/song?word=' + encodeURIComponent(kw) + '&page=' + searchPage + '&num=30').then(function (res) {
                if (!res || !res.data || res.data.length === 0) {
                    if (searchPage === 1) {
                        content.innerHTML = '<div style="padding:60px 20px;text-align:center"><div style="color:var(--textLight);font-size:15px">Không tìm thấy kết quả</div></div>';
                    }
                    hasMoreResults = false;
                    return;
                }

                var newSongs = [];
                res.data.forEach(function (item) {
                    var singerStr = 'Ca sĩ không xác định';
                    if (typeof item.singer === 'string') {
                        singerStr = item.singer;
                    } else if (Array.isArray(item.singer)) {
                        singerStr = item.singer.map(function (s) { return s.name || s; }).join('/');
                    }

                    var cover = item.cover;
                    if (!cover && item.albummid) cover = 'https://y.qq.com/music/photo_new/T002R300x300M000' + item.albummid + '.jpg';
                    if (!cover) cover = 'https://via.placeholder.com/100';

                    newSongs.push({
                        id: item.id || item.mid,
                        mid: item.mid,
                        name: item.song || item.songname || item.name || 'Bài hát không xác định',
                        singer: singerStr,
                        cover: cover
                    });
                });

                searchCache = searchCache.concat(newSongs);
                hasMoreResults = newSongs.length >= 30;
                renderSearchResults();
            });
        }

        function renderSearchResults() {
            if (!doc || !searchCache.length) return;
            var content = doc.getElementById('content');
            if (!content) return;

            var songs = searchCache;
            var html = '<div style="padding:20px 20px 120px">';
            html += '<div style="display:flex;align-items:center;margin-bottom:20px">';
            html += '<div id="back-home" style="cursor:pointer;color:var(--primary);margin-right:8px;display:flex;align-items:center;font-size:17px;font-weight:500">' + I.back + ' <span style="transform:translateY(-1px)">Trở lại</span></div>';
            html += '</div>';

            html += '<h2 style="font-size:28px;font-weight:700;color:var(--text);margin:0 0 20px;letter-spacing:-0.5px">Kết quả tìm kiếm</h2>';
            html += '<div style="display:flex;flex-direction:column;gap:0">';

            songs.forEach(function (s, i) {
                var isActive = state.currentSong && state.currentSong.id === s.id;
                html += '<div class="song-item touch-active" data-idx="' + i + '" style="display:flex;align-items:center;gap:12px;padding:12px 0;border-bottom:0.5px solid var(--border);cursor:pointer;position:relative">';
                html += '<img src="' + s.cover + '" style="width:50px;height:50px;border-radius:8px;object-fit:cover;background:var(--border);flex-shrink:0">';
                html += '<div style="flex:1;min-width:0">';
                html += '<div style="font-weight:500;font-size:16px;color:' + (isActive ? 'var(--primary)' : 'var(--text)') + ';overflow:hidden;text-overflow:ellipsis;white-space:nowrap;margin-bottom:2px">' + s.name + '</div>';
                html += '<div style="font-size:14px;color:var(--textLight)">' + s.singer + '</div>';
                html += '</div>';
                if (isActive) html += '<div style="width:16px;color:var(--primary)">♬</div>';
                html += '<div class="add-to-pl" data-idx="' + i + '" style="cursor:pointer;display:flex;padding:8px;color:var(--textLight)" title="Thêm vào Playlist" onclick="event.stopPropagation()">' + I.addList + '</div>';
                html += '<div data-fav="' + s.id + '" style="cursor:pointer;display:flex;padding:8px;color:var(--textLight)" onclick="event.stopPropagation()">' + (isFav(s.id) ? I.heartFill : I.heart) + '</div>';
                html += '</div>';
            });
            html += '</div>';

            if (hasMoreResults) {
                html += '<div id="load-more" style="text-align:center;padding:20px;color:var(--textLight);cursor:pointer;font-size:14px;font-weight:500">Tải thêm...</div>';
            }
            html += '</div>';

            content.innerHTML = html;

            doc.getElementById('back-home').onclick = function () { switchTab(currentTab); };

            var loadMoreBtn = doc.getElementById('load-more');
            if (loadMoreBtn) {
                loadMoreBtn.onclick = function () {
                    loadMoreBtn.textContent = 'Loading...';
                    search(searchKeyword, searchPage + 1);
                };
            }

            doc.querySelectorAll('.song-item').forEach(function (el) {
                el.onclick = function () {
                    var idx = parseInt(el.dataset.idx);
                    playSong(songs[idx], songs, 'Tìm kiếm: ' + searchKeyword, idx);
                };
            });

            doc.querySelectorAll('.add-to-pl').forEach(function(el) {
                el.onclick = function(e) {
                    e.stopPropagation();
                    showAddToPlaylistModal(songs[parseInt(el.dataset.idx)]);
                };
            });

            bindFavBtns(songs);
        }

        // ============ Modal Quản lý Playlist ============
        function showAddToPlaylistModal(song) {
            pendingSongToAdd = song;
            var modal = doc.getElementById('pl-modal');
            var list = doc.getElementById('pl-modal-list');
            if(!modal || !list) return;

            var html = '';
            if (state.playlists.length === 0) {
                html = '<div style="text-align:center;color:var(--textLight);padding:20px">Chưa có danh sách phát nào.<br><br><button id="btn-create-pl-modal" style="padding:10px 20px;border:none;background:var(--primary);color:#fff;border-radius:20px;font-weight:600;cursor:pointer">Tạo mới</button></div>';
            } else {
                state.playlists.forEach(function(pl, i) {
                    html += '<div class="pl-modal-item touch-active" data-idx="' + i + '" style="padding:16px 0;border-bottom:1px solid var(--border);color:var(--text);font-size:16px;font-weight:500;cursor:pointer">' + pl.name + ' <span style="color:var(--textLight);font-size:14px">(' + pl.songs.length + ' bài)</span></div>';
                });
            }
