            modal.style.display = 'flex';

            doc.getElementById('close-pl-modal').onclick = function() { modal.style.display = 'none'; };

            var createBtn = doc.getElementById('btn-create-pl-modal');
            if(createBtn) {
                createBtn.onclick = function() {
                    var name = prompt('Nhập tên danh sách phát mới:');
                    if (name && name.trim()) {
                        state.playlists.push({ id: Date.now(), name: name.trim(), songs: [] });
                        save();
                        showAddToPlaylistModal(pendingSongToAdd);
                    }
                };
            }

            list.querySelectorAll('.pl-modal-item').forEach(function(el) {
                el.onclick = function() {
                    var idx = parseInt(el.dataset.idx);
                    var pl = state.playlists[idx];
                    if (!pl.songs.some(function(s) { return s.id === pendingSongToAdd.id; })) {
                        pl.songs.push(pendingSongToAdd);
                        save();
                        if (window.parent.toastr) window.parent.toastr.success('Đã thêm vào ' + pl.name);
                    } else {
                        if (window.parent.toastr) window.parent.toastr.info('Bài hát đã tồn tại trong ' + pl.name);
                    }
                    modal.style.display = 'none';
                    if (currentTab === 'lib') renderLibrary(); 
                };
            });
        }

