        // Cập nhật Render danh sách nhạc để tích hợp Drag & Drop cải tiến
        function renderSongList(songs, title, type, playlistId) {
            if (!doc) return;
            var content = doc.getElementById('content');
            var html = '<div style="padding:20px 20px 120px">';

            var canDrag = (type === 'playlist' || type === 'fav');

            html += '<div style="display:flex;align-items:center;margin-bottom:20px">';
            html += '<div id="back-lib" style="cursor:pointer;color:var(--primary);margin-right:8px;display:flex;align-items:center;font-size:17px;font-weight:500">' + I.back + ' <span style="transform:translateY(-1px)">Trở lại</span></div>';
            html += '</div>';

            html += '<h2 style="font-size:32px;font-weight:800;color:var(--text);margin:0 0 24px;letter-spacing:-1px">' + title + '</h2>';

            if (songs.length === 0) {
                html += '<div style="text-align:center;padding:60px 0;color:var(--textLight)">Tạm thời chưa có bài hát</div>';
            } else {
                html += '<div id="play-all" style="background:var(--card);color:var(--primary);padding:14px;border-radius:12px;font-size:16px;font-weight:600;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:8px;margin-bottom:24px">' + I.play + ' Phát tất cả</div>';
            }

            html += '<div style="display:flex;flex-direction:column">';
            songs.forEach(function (s, i) {
                var isActive = state.currentSong && state.currentSong.id === s.id;
                html += '<div class="song-item touch-active" data-idx="' + i + '" ' + (canDrag ? 'draggable="true"' : '') + ' style="display:flex;align-items:center;gap:12px;padding:12px 0;border-bottom:0.5px solid var(--border);cursor:pointer;transition:background 0.2s">';

                if (canDrag) {
                    html += '<div class="drag-handle" style="color:var(--textLight);cursor:grab;padding-right:8px" title="Kéo để sắp xếp">' + I.drag + '</div>';
                }

                html += '<img src="' + s.cover + '" style="width:48px;height:48px;border-radius:6px;object-fit:cover;background:var(--border)">';
                html += '<div style="flex:1;min-width:0">';
                html += '<div style="font-weight:500;font-size:16px;color:' + (isActive ? 'var(--primary)' : 'var(--text)') + ';white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + s.name + '</div>';
                html += '<div style="font-size:14px;color:var(--textLight)">' + s.singer + '</div>';
                html += '</div>';

                if (type === 'playlist') {
                    html += '<div class="remove-from-pl" data-idx="' + i + '" style="cursor:pointer;padding:8px;color:var(--heart)" title="Xóa khỏi Playlist" onclick="event.stopPropagation()">' + I.delete + '</div>';
                } else {
                    html += '<div class="add-to-pl-list" data-idx="' + i + '" style="cursor:pointer;padding:8px;color:var(--textLight)" title="Thêm vào Playlist" onclick="event.stopPropagation()">' + I.addList + '</div>';
                    html += '<div data-fav="' + s.id + '" style="cursor:pointer;display:flex;padding:8px;color:var(--textLight)" onclick="event.stopPropagation()">' + (isFav(s.id) ? I.heartFill : I.heart) + '</div>';
                }
                html += '</div>';
            });
            html += '</div></div>';
            content.innerHTML = html;

            doc.getElementById('back-lib').onclick = function() { switchTab('lib'); };

            var playAllBtn = doc.getElementById('play-all');
            if (playAllBtn && songs.length > 0) {
                playAllBtn.onclick = function () { playSong(songs[0], songs, title, 0); };
            }

            doc.querySelectorAll('.song-item').forEach(function(el) {
                el.onclick = function() { playSong(songs[parseInt(el.dataset.idx)], songs, title, parseInt(el.dataset.idx)); };
            });

            // Logic Drag & Drop cải tiến (Kéo thả dạng danh sách dọc)
            if (canDrag) {
                var dragSrcIdx = null;
                doc.querySelectorAll('.song-item').forEach(function(item) {
                    item.addEventListener('dragstart', function(e) {
                        dragSrcIdx = parseInt(this.dataset.idx);
                        e.dataTransfer.effectAllowed = 'move';
                        e.dataTransfer.setData('text/plain', this.dataset.idx);
                        // Làm mờ đối tượng gốc khi đang được kéo đi
                        setTimeout(() => this.style.opacity = '0.4', 0); 
                    });

                    item.addEventListener('dragover', function(e) {
                        e.preventDefault();
                        e.dataTransfer.dropEffect = 'move';

                        var rect = this.getBoundingClientRect();
                        var relY = e.clientY - rect.top;

                        // Kẻ viền chỉ thị vị trí thả (trên hoặc dưới bài hát đang trỏ tới)
                        if (relY < rect.height / 2) {
                            this.style.borderTop = '2px solid var(--primary)';
                            this.style.borderBottom = '0.5px solid var(--border)';
                        } else {
                            this.style.borderTop = 'none';
                            this.style.borderBottom = '2px solid var(--primary)';
                        }
                        return false;
                    });

                    item.addEventListener('dragleave', function(e) {
                        this.style.borderTop = 'none';
                        this.style.borderBottom = '0.5px solid var(--border)';
                    });

                    item.addEventListener('drop', function(e) {
                        e.stopPropagation();
                        this.style.borderTop = 'none';
                        this.style.borderBottom = '0.5px solid var(--border)';

                        if (dragSrcIdx !== null) {
                            var fromIdx = dragSrcIdx;
                            var toIdx = parseInt(this.dataset.idx);

                            var rect = this.getBoundingClientRect();
                            var relY = e.clientY - rect.top;

                            // Nếu thả ở nửa dưới của phần tử đích, điều chỉnh index để chèn vào ngay sau nó
                            if (relY >= rect.height / 2) {
                                toIdx++;
                            }

                            // Điều chỉnh lại index nếu phần tử bị dời đi nằm trước đích do độ dài mảng co lại
                            if (fromIdx < toIdx) toIdx--;

                            if (fromIdx !== toIdx) {
                                var listToUpdate = type === 'playlist' ? state.playlists.find(function(p){return p.id===playlistId}).songs : state.favorites;
                                var movedItem = listToUpdate.splice(fromIdx, 1)[0];
                                listToUpdate.splice(toIdx, 0, movedItem);

                                save();
                                renderSongList(listToUpdate, title, type, playlistId);
                            }
                        }
                        return false;
                    });

                    item.addEventListener('dragend', function(e) {
                        this.style.opacity = '1';
                        // Reset lại border của tất cả list item phòng trường hợp lỗi graphic
                        doc.querySelectorAll('.song-item').forEach(function (el) {
                            el.style.borderTop = 'none';
                            el.style.borderBottom = '0.5px solid var(--border)';
                        });
                    });
                });
            }

            if (type === 'playlist') {
                doc.querySelectorAll('.remove-from-pl').forEach(function(el) {
                    el.onclick = function(e) {
                        e.stopPropagation();
                        var idx = parseInt(el.dataset.idx);
                        var pl = state.playlists.find(function(p) { return p.id === playlistId; });
                        if (pl) {
                            pl.songs.splice(idx, 1);
                            save();
                            renderSongList(pl.songs, title, type, playlistId);
                        }
                    };
                });
            } else {
                doc.querySelectorAll('.add-to-pl-list').forEach(function(el) {
                    el.onclick = function(e) {
                        e.stopPropagation();
                        showAddToPlaylistModal(songs[parseInt(el.dataset.idx)]);
                    };
                });
            }

            bindFavBtns(songs);
        }

